-- Vernen Legal Compliance — Washington State Compliance Rules (Seed Washington-2)
-- LICENSING, PRIVACY, INSURANCE, ENVIRONMENTAL, CONSUMER_PROTECTION, HEALTHCARE, REAL_ESTATE, CANNABIS
-- 180 rules with real RCW citations
-- Created: April 5, 2026

-- ============================================================
-- SECTION 1: LICENSING (35 rules) — wa-lic-001 to wa-lic-035
-- ============================================================

-- Contractor Registration (RCW 18.27)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-001', 'WA-LIC-001', 'General Contractor Registration — L&I', 'All contractors performing construction, alteration, repair, or other work on real or personal property in Washington must register with the Department of Labor and Industries. General contractors must post a surety bond of $12,000 and maintain current liability insurance with minimum $50,000/$100,000 bodily injury and $15,000 property damage. Registration must be renewed annually. Unregistered contractors face civil penalties up to $10,000 per violation and criminal misdemeanor charges.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.27.020; RCW 18.27.040', 'https://lni.wa.gov/licensing-permits/contractors/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-002', 'WA-LIC-002', 'Specialty Contractor Registration and Bond', 'Specialty contractors (working in a single trade such as plumbing, electrical, HVAC) must register with L&I with a $6,000 surety bond. Contractors performing work valued over $30,000 on a single project must carry a $12,000 bond. Bond amounts increase to $30,000 for contractors with documented claims or violations. Registration number must appear on all contracts, bids, and advertisements.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.27.040; WAC 296-200A-015', 'https://lni.wa.gov/licensing-permits/contractors/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-003', 'WA-LIC-003', 'Contractor Insurance Requirements', 'Registered contractors must maintain commercial general liability insurance and file proof with L&I. Minimum coverage: $50,000 per occurrence bodily injury, $100,000 aggregate bodily injury, $15,000 property damage. Contractors must also maintain workers'' compensation coverage through the state fund or be qualified as a self-insurer. Insurance must remain current throughout the registration period. Lapse triggers automatic suspension.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.27.050; RCW 18.27.060', 'https://lni.wa.gov/licensing-permits/contractors/', 1);

-- Electrical Licensing (RCW 19.28)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-004', 'WA-LIC-004', 'Electrical Contractor License', 'Electrical contractors must obtain a license from L&I before performing or offering to perform electrical work. Applicants must designate a master electrician or administrator, carry a $4,000 surety bond, maintain liability insurance, and have active workers'' compensation coverage. License must be renewed annually. Performing electrical work without a license is a gross misdemeanor under RCW 19.28.041.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 19.28.041; RCW 19.28.061', 'https://lni.wa.gov/licensing-permits/electrical/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-005', 'WA-LIC-005', 'Journeyman Electrician Certificate', 'Individuals performing electrical work must hold a valid certificate of competency. Journey-level electricians must complete 8,000 hours of supervised experience under a certified master or journey-level electrician and pass the state examination. Specialties include general journey (01), residential (02), pump and irrigation (03), signs (04), limited energy (06), and HVAC/R (06A). Certificates must be renewed every three years with 24 hours of continuing education.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 19.28.191; WAC 296-46B-940', 'https://lni.wa.gov/licensing-permits/electrical/electrical-certifications', 1);

-- Plumbing (RCW 18.106)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-006', 'WA-LIC-006', 'Plumber Certification — Journey Level', 'Journey-level plumbers must hold a certificate of competency issued by L&I. Requirements include completion of an approved 4-year apprenticeship (8,000 hours) or equivalent experience, and passing the state plumbing examination. Certificates must be renewed every two years with continuing education. Working without certification is a gross misdemeanor. Plumbing work must conform to the Uniform Plumbing Code as adopted by Washington.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.106.070; RCW 18.106.020', 'https://lni.wa.gov/licensing-permits/plumbing/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-007', 'WA-LIC-007', 'Plumbing Contractor License', 'Plumbing contractors must register with L&I, designate a journey-level or specialty plumber, and comply with contractor registration requirements under RCW 18.27. Plumbing permits must be obtained from the local jurisdiction before work begins. All plumbing work must comply with the current edition of the Uniform Plumbing Code as amended by the state building code council under RCW 19.27.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.106.010; RCW 18.27.020', 'https://lni.wa.gov/licensing-permits/plumbing/', 1);

-- Professional Engineers (RCW 18.43)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-008', 'WA-LIC-008', 'Professional Engineer License', 'Engineers practicing in Washington must be licensed by the Board of Registration for Professional Engineers and Land Surveyors. Requirements include an ABET-accredited engineering degree, four years of progressive engineering experience, and passing the FE and PE examinations. License renewed annually. Practicing without a license or using the title "professional engineer" without licensure is a gross misdemeanor under RCW 18.43.120.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.43.040; RCW 18.43.060', 'https://brpels.wa.gov/', 1);

-- Real Estate (RCW 18.85)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-009', 'WA-LIC-009', 'Real Estate Broker License', 'Real estate brokers must be licensed by the Washington Department of Licensing. Requirements include 90 clock hours of approved pre-license education, passing the state and national examinations, and affiliation with a designated or managing broker. Licenses renewed every two years with 30 hours of continuing education including a required 3-hour core course. Practicing without a license subjects individuals to penalties under RCW 18.85.361.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.85.101; RCW 18.85.111', 'https://www.dol.wa.gov/business/realestate/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-010', 'WA-LIC-010', 'Real Estate Managing Broker License', 'Managing brokers must complete 150 clock hours of approved education (including the 90-hour broker requirement), have at least three years of full-time real estate experience within the preceding five years, and pass the managing broker examination. Managing brokers supervise affiliated brokers and are responsible for the firm''s compliance with the Real Estate Brokerage Relationships Act under RCW 18.86.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.85.101; RCW 18.85.161', 'https://www.dol.wa.gov/business/realestate/', 1);

-- Insurance Producers (RCW 48.17)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-011', 'WA-LIC-011', 'Insurance Producer License', 'Insurance producers must be licensed by the Office of the Insurance Commissioner before selling, soliciting, or negotiating insurance in Washington. Applicants must complete pre-licensing education (40 hours for property/casualty, 20 hours for life/disability), pass the state examination, submit fingerprints for background check, and designate lines of authority. License renewed biennially with 24 hours of continuing education.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 48.17.060; RCW 48.17.090', 'https://www.insurance.wa.gov/licensing', 1);

-- Cannabis (RCW 69.50 — WSLCB)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-012', 'WA-LIC-012', 'Cannabis Producer License — WSLCB', 'Cannabis producers must obtain a license from the Washington State Liquor and Cannabis Board (WSLCB). Applicants undergo background checks, source of funds review, and premises inspection. Producer licenses are tiered by canopy size: Tier 1 (up to 2,000 sq ft), Tier 2 (2,000-10,000 sq ft), Tier 3 (10,000-30,000 sq ft). Annual renewal required. All production must occur in a fully enclosed, secure facility compliant with WAC 314-55-083.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.325; WAC 314-55-075', 'https://lcb.wa.gov/mjlicense/marijuana-licensing', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-013', 'WA-LIC-013', 'Cannabis Processor License — WSLCB', 'Cannabis processor licenses authorize the processing, packaging, and labeling of cannabis products including usable marijuana, concentrates, and infused products. Processors must maintain food safety standards, comply with the state food processing rules, and ensure all products meet testing requirements before transfer to retailers. Processing facilities must be separate from production areas unless co-located under a producer/processor license.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.325; WAC 314-55-077', 'https://lcb.wa.gov/mjlicense/marijuana-licensing', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-014', 'WA-LIC-014', 'Cannabis Retailer License — WSLCB', 'Cannabis retail licenses authorize the sale of usable marijuana, marijuana concentrates, and marijuana-infused products to consumers 21 and older. Retailers must verify age with valid government ID. No retail store may be located within 1,000 feet of elementary or secondary schools, playgrounds, recreation centers, child care centers, public parks, public transit centers, libraries, or game arcades. Retailers may not sell cannabis below their acquisition cost.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.325; WAC 314-55-079', 'https://lcb.wa.gov/mjlicense/marijuana-licensing', 1);

-- Liquor (WSLCB)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-015', 'WA-LIC-015', 'Liquor License — WSLCB', 'Businesses selling or serving alcohol in Washington must hold an appropriate liquor license from the WSLCB. License types include spirits/beer/wine restaurant, beer/wine restaurant, tavern, hotel, caterer, and microbrewery/winery/distillery. Applications require local jurisdiction approval, floor plans, background checks, and applicable fees ranging from $100 to $2,000 annually. Mandatory Alcohol Server Training (MAST) permit required for all servers within 60 days of employment.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 66.24.010; RCW 66.20.300', 'https://lcb.wa.gov/licensing/apply-for-a-liquor-license', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-016', 'WA-LIC-016', 'Mandatory Alcohol Server Training Permit', 'All persons who serve, mix, or sell alcohol at licensed premises must obtain a MAST permit from the WSLCB or an approved training provider within the first 60 days of employment. Permits are valid for five years. Training covers responsible service, signs of intoxication, ID verification, and liability. Employers are responsible for ensuring all employees hold current permits. Failure to comply may result in license sanctions.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 66.20.310; RCW 66.20.320', 'https://lcb.wa.gov/mast/mandatory-alcohol-server-training', 1);

-- Cosmetology/Barber
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-017', 'WA-LIC-017', 'Cosmetologist License', 'Cosmetologists must be licensed by the Department of Licensing. Requirements include completion of 1,600 hours of approved cosmetology school training or an apprenticeship program, and passing the state examination. License covers hair, skin, and nail services. Renewed annually with continuing education. Salons must hold a separate facility license and pass DOH sanitation inspections. Practicing without a license is a misdemeanor.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.16.020; RCW 18.16.050', 'https://www.dol.wa.gov/business/cosmetology/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-018', 'WA-LIC-018', 'Barber License', 'Barbers must be licensed by the Department of Licensing after completing 1,000 hours of approved barber school training and passing the state examination. Barber services include haircutting, shaving, trimming, shampooing, and scalp treatments. Barber shops require a separate facility license. All shops must comply with sanitation requirements under WAC 308-20. License renewed annually.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.16.020; WAC 308-20-080', 'https://www.dol.wa.gov/business/cosmetology/', 1);

-- Pharmacy
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-019', 'WA-LIC-019', 'Pharmacy License', 'Every pharmacy operating in Washington must hold a pharmacy license issued by the Washington State Department of Health Pharmacy Quality Assurance Commission. Pharmacies must be under the supervision of a licensed pharmacist at all times when open. License requires annual renewal, inspection compliance, controlled substance registration, and compliance with USP standards for compounding if applicable. Out-of-state pharmacies shipping to WA must hold a nonresident pharmacy license.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 18.64.043; WAC 246-869-010', 'https://doh.wa.gov/licenses-permits-and-certificates/professions-new-renew-702/pharmacist', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-020', 'WA-LIC-020', 'Pharmacist License', 'Pharmacists must be licensed by the Pharmacy Quality Assurance Commission. Requirements include graduation from an ACPE-accredited pharmacy program, passing NAPLEX and MPJE examinations, completion of 1,500 hours of supervised internship, and a background check. Licensed pharmacists may administer vaccines under collaborative practice agreements. Licenses renewed annually with 15 hours of continuing education.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.64.005; RCW 18.64.080', 'https://doh.wa.gov/licenses-permits-and-certificates/professions-new-renew-702/pharmacist', 1);

-- Nursing
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-021', 'WA-LIC-021', 'Registered Nurse License', 'Registered nurses must be licensed by the Washington State Nursing Care Quality Assurance Commission. Requirements include graduation from an approved nursing program, passing the NCLEX-RN examination, and submitting fingerprints for a background check. Washington participates in the enhanced Nurse Licensure Compact (eNLC) effective 2025, allowing multistate practice. License renewed every two years with 531 hours of practice and 8 hours of continuing education in AIDS.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 18.79.050; RCW 18.79.110', 'https://doh.wa.gov/licenses-permits-and-certificates/professions-new-renew-702/nurse', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-022', 'WA-LIC-022', 'Advanced Registered Nurse Practitioner License', 'ARNPs must hold a registered nurse license and complete an approved master''s or doctoral program in a nursing specialty. ARNPs may diagnose, prescribe medications (including controlled substances with DEA registration), order diagnostic tests, and manage patient care independently. Prescriptive authority requires a pharmacology course of at least 30 hours. License renewed every two years with 250 practice hours and 30 hours of continuing education.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 18.79.050; RCW 18.79.250', 'https://doh.wa.gov/licenses-permits-and-certificates/professions-new-renew-702/nurse', 1);

-- General Business License
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-023', 'WA-LIC-023', 'City General Business License', 'Most Washington cities require a general business license for businesses operating within city limits. Requirements, fees, and renewal schedules vary by municipality. Many cities participate in the state''s Business Licensing Service (BLS) allowing application through a single portal. Seattle requires a separate City Business License Tax Certificate. Businesses with locations in multiple cities may need licenses in each jurisdiction.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 35.90.020; Municipal Codes', 'https://bls.dor.wa.gov/', 1);

-- Master Business License
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-024', 'WA-LIC-024', 'Master Business License — Business Licensing Service', 'Washington''s Business Licensing Service (formerly Master License Service) provides a single application for state and local business licenses, tax registrations, and endorsements. All businesses must register for a UBI (Unified Business Identifier) number. The system handles Department of Revenue tax registration, city business licenses, and select specialty endorsements. Annual renewal required. Registration is mandatory for all business entities operating in Washington.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.02.020; RCW 19.02.070', 'https://bls.dor.wa.gov/', 1);

-- Food Establishment Permits (DOH)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-025', 'WA-LIC-025', 'Food Establishment Permit — DOH', 'Food establishments must obtain a permit from the local health jurisdiction or the Washington State Department of Health. Permits require a plan review, facility inspection, and demonstration of compliance with the Washington State Food Code (WAC 246-215). Food worker cards are required for all employees who handle food or food-contact surfaces — cards are obtained by passing a food safety knowledge test and are valid for two years.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 69.06.010; WAC 246-215', 'https://doh.wa.gov/community-and-environment/food-safety', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-026', 'WA-LIC-026', 'Food Worker Card', 'Every person involved in food handling or preparation in a food establishment must obtain a Washington State Food Worker Card within 14 days of beginning employment. The card is obtained by completing training and passing a test on food safety fundamentals including temperature control, cross-contamination prevention, personal hygiene, and allergen management. Cards are valid for two years and accepted statewide. Employers must verify current cards for all food-handling staff.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 69.06.010; RCW 69.06.020', 'https://www.foodworkercard.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-027', 'WA-LIC-027', 'Cottage Food Permit', 'Washington''s Cottage Food Law allows individuals to produce and sell certain low-risk foods from their home kitchen without a full commercial food establishment permit. Annual sales are capped at $75,000 (increased from $25,000 in 2023). Allowed products include baked goods, jams, candies, and other shelf-stable items. Labels must include cottage food operation name, address, ingredients, allergens, and the statement "Made in a home kitchen that has not been inspected by the department of health."', 'LICENSING', 'STATE', 'WA', '["SOLE_PROPRIETORSHIP","LLC"]', '2024-01-01', 'RCW 69.22.010; RCW 69.22.040', 'https://doh.wa.gov/community-and-environment/food-safety/cottage-food', 1);

-- Child Care Licensing
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-028', 'WA-LIC-028', 'Child Care Center License — DCYF', 'Child care centers must be licensed by the Department of Children, Youth, and Families (DCYF). Centers must meet requirements for staff-to-child ratios (1:4 for infants, 1:7 for toddlers, 1:10 for preschool), facility safety, background checks for all staff, health and nutrition standards, and outdoor play space. Initial license requires a full inspection. Licenses renewed annually. Operating without a license is a gross misdemeanor under RCW 43.216.365.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 43.216.250; WAC 110-300', 'https://www.dcyf.wa.gov/services/early-learning-providers/licensed-child-care', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-029', 'WA-LIC-029', 'Family Home Child Care License — DCYF', 'Family home child care providers caring for children of more than one family must be licensed by DCYF. Licensed family homes may care for up to 12 children. Providers must complete 20 hours of pre-service STARS training, first aid/CPR, pass background checks, and maintain a safe home environment. Annual continuing education of 10 hours required. Licensed providers are eligible to participate in the state''s Early Achievers quality rating system and receive subsidy payments.', 'LICENSING', 'STATE', 'WA', '["SOLE_PROPRIETORSHIP","LLC"]', '2024-01-01', 'RCW 43.216.250; WAC 110-300-0015', 'https://www.dcyf.wa.gov/services/early-learning-providers/licensed-child-care', 1);

-- Additional professional licensing
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-030', 'WA-LIC-030', 'Architect License', 'Architects must be licensed by the Board of Registration for Architects to practice or use the title "architect" in Washington. Requirements include a NAAB-accredited degree, completion of the Architectural Experience Program (AXP), and passing all divisions of the Architect Registration Examination (ARE). License renewed annually with continuing education. Firms offering architectural services must register with the board.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.08.310; RCW 18.08.350', 'https://brpels.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-031', 'WA-LIC-031', 'Private Investigator License', 'Private investigators must be licensed by the Department of Licensing. Requirements include passing a background check, providing proof of insurance ($25,000 bond or equivalent), and demonstrating qualifying experience (3 years of investigative experience or a combination of education and experience). Armed investigators must additionally obtain a firearms certificate. Licenses renewed annually. Employing unlicensed investigators is a gross misdemeanor.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.165.030; RCW 18.165.040', 'https://www.dol.wa.gov/business/securityguards/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-032', 'WA-LIC-032', 'Home Inspector License', 'Home inspectors must be licensed by the Department of Licensing. Requirements include completion of 120 hours of approved education, passing the national examination, and completing 40 supervised inspections. Licensed inspectors must carry errors and omissions insurance of at least $100,000 per occurrence. License renewed every two years with 24 hours of continuing education. Inspectors must follow the Standards of Practice under WAC 308-408C.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.280.030; WAC 308-408C', 'https://www.dol.wa.gov/business/homeinspectors/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-033', 'WA-LIC-033', 'Motor Vehicle Dealer License', 'Motor vehicle dealers must be licensed by the Department of Licensing. Requirements include a permanent established place of business, surety bond ($25,000 for new vehicle dealers, $25,000 for used), proof of business entity registration, and compliance with facility requirements including display space and signage. Dealer license must be renewed annually. Selling three or more vehicles in a 12-month period without a license constitutes unlicensed dealing.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 46.70.021; RCW 46.70.023', 'https://www.dol.wa.gov/business/vehicledealer/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-034', 'WA-LIC-034', 'Notary Public Commission', 'Notaries public must be commissioned by the Department of Licensing. Applicants must be Washington residents or work in Washington, be at least 18, read and write English, and not have had a commission revoked in the past 10 years. Commission valid for four years. Notaries must post a $10,000 surety bond. Remote online notarization (RON) authorized under RCW 42.45 with additional technology requirements and $25,000 bond.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 42.45.010; RCW 42.45.200', 'https://www.dol.wa.gov/business/notary/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-lic-035', 'WA-LIC-035', 'Landscape Architect License', 'Landscape architects must be licensed by the Board of Registration for Landscape Architects. Requirements include a LAAB-accredited degree, completion of at least two years of supervised experience, and passing the Landscape Architect Registration Examination (LARE). Using the title "landscape architect" without a license is prohibited. Firms providing landscape architecture services must register with the board. License renewed annually with continuing education.', 'LICENSING', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.96.060; RCW 18.96.080', 'https://brpels.wa.gov/', 1);

-- ============================================================
-- SECTION 2: PRIVACY (25 rules) — wa-prv-001 to wa-prv-025
-- ============================================================

-- My Health My Data Act
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-001', 'WA-PRV-001', 'My Health My Data Act — Consent for Health Data Collection', 'The Washington My Health My Data Act (2023) requires regulated entities to obtain affirmative, voluntary consent before collecting consumer health data. Consent must be separate and distinct from general terms of use or service agreements. The act covers entities not subject to HIPAA including health apps, fitness trackers, telehealth platforms, and any business collecting health data. Small businesses (under 100,000 consumers) had compliance deadline June 30, 2024; large businesses March 31, 2024.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.373.010; RCW 19.373.030', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.373', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-002', 'WA-PRV-002', 'My Health My Data Act — Consumer Health Data Definition', 'The Act defines "consumer health data" extremely broadly to include any information that identifies or reasonably links to a consumer and relates to physical or mental health, including bodily functions, vital signs, diagnoses, treatments, medications, reproductive or sexual health, gender-affirming care, biometric data, genetic data, location data that could indicate healthcare visits, and health-related inferences drawn from non-health data.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.373.010(8)', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.373.010', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-003', 'WA-PRV-003', 'My Health My Data Act — Privacy Policy Requirements', 'Regulated entities must maintain a consumer health data privacy policy that clearly discloses the categories of health data collected, the purpose of collection, the categories of sources, the categories of third parties with whom data is shared, and how consumers can exercise their rights. Policy must be prominently available on the entity''s website or application. Generic privacy policies that do not specifically address health data do not satisfy this requirement.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.373.020', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.373.020', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-004', 'WA-PRV-004', 'My Health My Data Act — Right to Delete Health Data', 'Consumers have the right to request deletion of their consumer health data. Regulated entities must comply within 30 days and must also direct all affiliates, processors, contractors, and other third parties to delete the data. The entity must provide a mechanism for consumers to exercise deletion rights. Exceptions apply for data required for legal compliance, completing a transaction, or preventing fraud.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.373.040', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.373.040', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-005', 'WA-PRV-005', 'My Health My Data Act — Sale of Health Data Prohibited Without Authorization', 'The sale of consumer health data is prohibited without valid authorization that is separate from any consent to collect or share. Authorization must specify the health data being sold, the name and contact information of the purchaser, the purpose of the sale, and a clear statement that the consumer may revoke authorization at any time. Violations enforceable under the Consumer Protection Act with private right of action.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.373.050', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.373.050', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-006', 'WA-PRV-006', 'My Health My Data Act — Geofencing Prohibition', 'It is unlawful to implement a geofence around any entity that provides in-person healthcare services where the geofence is used to identify or track consumers seeking healthcare, collect health data, or send notifications, messages, or advertisements to consumers. This prohibition specifically targets anti-abortion geofencing but applies broadly to any healthcare facility geofencing for data collection purposes.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.373.060', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.373.060', 1);

-- Data Breach Notification
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-007', 'WA-PRV-007', 'Data Breach Notification — 30-Day Timeline', 'Any person or business that owns or licenses computerized data containing personal information must notify affected Washington residents within 30 days of discovery of a breach. Notification must include a description of the incident, type of information involved, contact information, and toll-free numbers for credit reporting agencies. Notification delay permitted only at law enforcement request. Breaches affecting 500+ Washington residents require simultaneous notification to the Attorney General.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.255.010', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.255.010', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-008', 'WA-PRV-008', 'Data Breach — Definition of Personal Information', 'Personal information triggering breach notification includes a Washington resident''s first name or initial plus last name combined with: Social Security number, driver''s license or state ID number, account or credit/debit card number with security code/password, full date of birth, private key for electronic signature, student/military/passport ID, health insurance policy/ID number, medical history or condition, biometric data, username or email with password or security question answers.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.255.005(3)', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.255.005', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-009', 'WA-PRV-009', 'Data Breach — Attorney General Notification', 'If a data breach affects more than 500 Washington residents, the entity must notify the Washington Attorney General within 30 days of discovery. Notification must include a list of the types of personal information breached, the number of affected consumers, the timeline of the breach and discovery, a general description of the breach, the entity''s estimated date of notification, and whether the entity has offered identity theft protection services.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.255.010(15)', 'https://www.atg.wa.gov/data-breach-notifications', 1);

-- Biometric Identifiers
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-010', 'WA-PRV-010', 'Biometric Identifier Notice and Consent', 'Entities enrolling a biometric identifier (retina/iris scan, fingerprint, voiceprint, hand geometry, or any unique biological pattern) must provide notice that the identifier is being collected, provide notice of the specific purpose and length of term for which the identifier is being collected, and obtain affirmative consent from the individual. Biometric identifiers may not be sold, leased, or otherwise commercially disclosed without consent. Enforceable under the Consumer Protection Act.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.375.020', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.375', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-011', 'WA-PRV-011', 'Biometric Identifier Retention and Destruction', 'Entities that possess biometric identifiers must establish a retention schedule and guidelines for permanently destroying biometric identifiers when the initial purpose for collection has been satisfied or within three years of the individual''s last interaction with the entity, whichever comes first. The entity must comply with its published retention schedule and destruction guidelines. Storage must use reasonable security measures against unauthorized access.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.375.020(3)', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.375.020', 1);

-- Student Data Privacy
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-012', 'WA-PRV-012', 'Student Personal Information Protection — Service Providers', 'Operators of websites, online services, or applications used for K-12 school purposes may not use student data for targeted advertising, sell student information, or use collected information to create a profile of a student except in furtherance of K-12 school purposes. Operators must implement reasonable security procedures and delete student data within 60 days of request by the school or district. Violations are per se unfair or deceptive acts under the Consumer Protection Act.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 28A.604.010; RCW 28A.604.020', 'https://app.leg.wa.gov/RCW/default.aspx?cite=28A.604', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-013', 'WA-PRV-013', 'Student Education Records — FERPA State Compliance', 'Washington school districts must comply with FERPA requirements and state law regarding student education records. Parents and eligible students have the right to inspect, review, and request amendment of records. Directory information may be released only after annual notification and opt-out opportunity. Transcripts require written consent for release except to schools in which the student seeks enrollment. School districts must adopt policies consistent with RCW 28A.605.030.', 'PRIVACY', 'STATE', 'WA', '["NONPROFIT","LLC","CORPORATION"]', '2024-01-01', 'RCW 28A.605.030; WAC 392-182', 'https://app.leg.wa.gov/RCW/default.aspx?cite=28A.605.030', 1);

-- Employee Monitoring
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-014', 'WA-PRV-014', 'Employee Monitoring and Electronic Surveillance', 'Washington is a two-party consent state for recording private conversations under RCW 9.73.030. Employers recording or monitoring employee phone calls, emails, or other electronic communications must obtain consent from all parties. Secretly recording a private conversation is a gross misdemeanor. Employers should provide clear written notice of any monitoring policies. Exceptions exist for monitoring authorized by court order or recording communications with prior all-party consent.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 9.73.030; RCW 9.73.060', 'https://app.leg.wa.gov/RCW/default.aspx?cite=9.73.030', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-015', 'WA-PRV-015', 'Video Surveillance in the Workplace', 'While Washington law does not prohibit video surveillance in the workplace, employers must not place cameras in areas where employees have a reasonable expectation of privacy (restrooms, locker rooms, changing areas). Audio recording requires all-party consent under RCW 9.73.030. Employers should provide written notice of video surveillance policies. Video surveillance combined with audio recording in workplaces is subject to the state wiretapping statute and requires consent.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 9.73.030; Common Law Privacy', 'https://app.leg.wa.gov/RCW/default.aspx?cite=9.73', 1);

-- Facial Recognition
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-016', 'WA-PRV-016', 'Facial Recognition — State Agency Restrictions', 'Washington state agencies and local governments using facial recognition technology must file a notice of intent with the legislature, produce an accountability report, obtain meaningful consent before using the technology in ongoing surveillance, and test for accuracy and bias. Use is prohibited for ongoing surveillance of specific individuals except under an appropriate legal authority such as a warrant. Law enforcement must obtain a warrant or exigent circumstances. Public reports required annually.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 43.386.010; RCW 43.386.080', 'https://app.leg.wa.gov/RCW/default.aspx?cite=43.386', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-017', 'WA-PRV-017', 'Facial Recognition — Vendor Accountability', 'Companies providing facial recognition services to state and local agencies must make available an application programming interface or other means for agencies to test the service for accuracy and bias, provide documentation on the types of data used to train the system, prohibit the use of their service for real-time identification without documented legal authority, and make publicly available a statement of the facial recognition service''s intended purpose and limitations.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 43.386.090; RCW 43.386.100', 'https://app.leg.wa.gov/RCW/default.aspx?cite=43.386.090', 1);

-- Consumer Data Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-018', 'WA-PRV-018', 'Social Security Number Protection', 'Businesses and government agencies may not publicly post or display an individual''s Social Security number, require use of an SSN to access a website unless a password or unique PIN is also required, print an SSN on materials mailed to an individual unless required by law, or require transmission of an SSN over the internet unless encrypted or the connection is secure. Violations are enforceable under the Consumer Protection Act.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.255.020', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.255.020', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-019', 'WA-PRV-019', 'Financial Information Privacy — Insurance', 'Insurance companies, agents, and brokers licensed in Washington must comply with financial information privacy provisions requiring notice to consumers about information collection and sharing practices, offering consumers the opportunity to opt out of sharing nonpublic personal financial information with nonaffiliated third parties, and maintaining administrative, technical, and physical safeguards for the security of customer information.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 48.43.505; WAC 284-04-400', 'https://www.insurance.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-020', 'WA-PRV-020', 'Identity Theft Prevention — Consumer Rights', 'Washington provides strong identity theft protections including the right to place a security freeze on credit reports at no cost, the right to obtain police reports for identity theft claims, the right to dispute and block fraudulent information on credit reports, and civil remedies for identity theft victims. Businesses must cooperate with identity theft investigations by law enforcement upon presentation of a police report. Identity theft is a class C felony under RCW 9.35.020.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 9.35.020; RCW 19.182.170', 'https://app.leg.wa.gov/RCW/default.aspx?cite=9.35', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-021', 'WA-PRV-021', 'Disposal of Personal Information', 'Businesses and government agencies must take reasonable steps to destroy personal financial and health information when it is no longer needed. Destruction methods include shredding, erasing, or otherwise rendering the information unreadable or indecipherable. The duty applies to both paper and electronic records. Failure to properly dispose of personal information is a violation of the Consumer Protection Act and may result in civil penalties.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.215.020; RCW 19.215.030', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.215', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-022', 'WA-PRV-022', 'Commercial Electronic Message Spam Protections', 'It is unlawful to send a commercial electronic mail message from Washington or to a Washington email address that uses a third party''s domain name without permission, contains false or misleading information in the subject line, or does not contain a valid mechanism to opt out of future messages. Violations are per se unfair or deceptive acts under the Consumer Protection Act. The recipient may bring a civil action for actual damages or $500 per violation, whichever is greater.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.190.020; RCW 19.190.040', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.190', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-023', 'WA-PRV-023', 'Two-Party Consent for Recording Private Conversations', 'Washington requires consent of all parties before recording a private conversation, telephone call, or electronic communication. Recording without consent is a gross misdemeanor and may also give rise to civil liability including actual damages, statutory damages, and attorney fees. This applies to employers monitoring employee calls, businesses recording customer calls, and any private recording. An announcement at the start of a call that the call is being recorded may constitute implied consent if the other party continues.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 9.73.030; RCW 9.73.060', 'https://app.leg.wa.gov/RCW/default.aspx?cite=9.73.030', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-024', 'WA-PRV-024', 'Automatic License Plate Reader Privacy', 'State and local law enforcement using automatic license plate reader (ALPR) data must only use the data for criminal investigation, traffic safety, or stolen vehicle recovery. ALPR data not associated with an active investigation must be destroyed within 90 days unless relevant to an ongoing investigation. Agencies must log all access to ALPR data and adopt a privacy and use policy. ALPR data may not be sold or shared for commercial purposes.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 46.08.065', 'https://app.leg.wa.gov/RCW/default.aspx?cite=46.08.065', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-prv-025', 'WA-PRV-025', 'Data Protection for Reproductive and Gender-Affirming Care', 'Washington''s Shield Law (2023) prohibits state and local agencies from cooperating with out-of-state investigations into individuals seeking or providing lawful reproductive or gender-affirming healthcare in Washington. Health data related to these services receives enhanced protection under the My Health My Data Act. Health care providers may not disclose patient information related to reproductive or gender-affirming care in response to out-of-state legal process absent a Washington court order.', 'PRIVACY', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 7.115.010; HB 1469 (2023)', 'https://app.leg.wa.gov/RCW/default.aspx?cite=7.115', 1);

-- ============================================================
-- SECTION 3: INSURANCE (25 rules) — wa-ins-001 to wa-ins-025
-- ============================================================

-- Workers' Compensation (mandatory state fund)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-001', 'WA-INS-001', 'Workers'' Compensation — Mandatory State Fund', 'Washington is one of four states with a monopolistic state workers'' compensation fund. All employers must obtain industrial insurance through the Washington State Department of Labor and Industries — there is no option for private insurance carriers. Employers pay a base rate plus supplemental rates by risk classification. Both employers and employees share premium costs through payroll deductions. Coverage provides medical benefits, wage replacement, and vocational rehabilitation for work-related injuries and illnesses.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 51.16.060; RCW 51.12.010', 'https://lni.wa.gov/insurance/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-002', 'WA-INS-002', 'Workers'' Compensation — Self-Insurance Option', 'Large employers meeting financial requirements may apply to self-insure for workers'' compensation through L&I. Self-insured employers must demonstrate financial stability, post a surety bond or deposit securities, maintain qualified claims management staff, and submit to L&I audits. Self-insured employers pay assessments to the self-insured employer pension reserve fund, the second injury fund, and the supplemental pension fund. Application requires minimum 3 years in business and documented financial capacity.', 'INSURANCE', 'STATE', 'WA', '["CORPORATION","LLC"]', '2024-01-01', 'RCW 51.14.010; WAC 296-15-021', 'https://lni.wa.gov/insurance/self-insurance/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-003', 'WA-INS-003', 'Workers'' Compensation — Reporting and Claims Filing', 'Employers must report workplace injuries to L&I within 10 days using the Report of Industrial Injury or Occupational Disease form. Workers must file claims within one year of injury or within two years for occupational diseases. Employers may not discourage employees from filing claims. Discriminating against or terminating an employee for filing a workers'' compensation claim is prohibited under RCW 51.48.025 and subjects the employer to a penalty of the lesser of the claim costs or actual damages.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 51.28.010; RCW 51.48.025', 'https://lni.wa.gov/claims/', 1);

-- Unemployment Insurance
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-004', 'WA-INS-004', 'Unemployment Insurance — Employer Registration', 'Employers with one or more employees in Washington must register with the Employment Security Department (ESD) and pay unemployment insurance taxes. New employers receive an assigned tax rate based on industry classification. Experienced employers'' rates are adjusted annually based on their claims experience (benefit ratio method). The taxable wage base is adjusted annually — for 2024 it is $67,600. Employers must file quarterly tax reports and pay premiums timely to avoid penalties and interest.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50.24.010; RCW 50.29.025', 'https://esd.wa.gov/employer-taxes', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-005', 'WA-INS-005', 'Unemployment Insurance — Quarterly Reporting', 'Employers must file quarterly wage reports with ESD listing each employee''s name, Social Security number, hours worked, and gross wages. Reports and tax payments are due by the last day of the month following the end of each quarter (April 30, July 31, October 31, January 31). Late filing penalties range from $25 to 10% of quarterly taxes due. Electronic filing required for employers with 25+ employees.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50.12.070; RCW 50.12.080', 'https://esd.wa.gov/employer-taxes/reporting-and-filing', 1);

-- Paid Family Medical Leave
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-006', 'WA-INS-006', 'Paid Family and Medical Leave — Premium Requirements', 'Washington''s Paid Family and Medical Leave (PFML) program requires employers to remit premiums to ESD. The 2024 total premium rate is 0.74% of wages up to the Social Security cap. Employers with 50+ employees must pay at least 26.78% of the medical leave portion; the remainder is the employee''s share. Employers with fewer than 50 employees are not required to pay the employer share but must collect and remit the employee share. Small business grants available for coverage costs.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50A.10.030; WAC 192-500-010', 'https://paidleave.wa.gov/employers/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-007', 'WA-INS-007', 'Paid Family and Medical Leave — Benefit Eligibility', 'Employees who have worked at least 820 hours in the qualifying period are eligible for up to 12 weeks of family leave (bonding, family member care), 12 weeks of medical leave (own serious health condition), or a combined maximum of 16 weeks if both apply. An additional 2 weeks may be available for pregnancy complications (18 weeks total). Benefits replace up to 90% of wages for lower earners with a weekly maximum ($1,456 in 2024). Job protection applies if the employer has 50+ employees and the worker has been employed 12+ months.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50A.15.020; RCW 50A.05.010', 'https://paidleave.wa.gov/', 1);

-- WA Cares Fund
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-008', 'WA-INS-008', 'WA Cares Fund — Long-Term Care Insurance Premium', 'The WA Cares Fund is a state-run long-term care insurance program funded by a 0.58% employee-paid premium on gross wages with no cap. Employers must collect and remit premiums quarterly to ESD. Workers who had qualifying private long-term care insurance by November 1, 2021, could apply for an exemption. Tribal members and certain nonimmigrant visa holders may also be exempt. Born-before-1968 workers have limited benefit eligibility based on contribution years.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50B.04.080; RCW 50B.04.020', 'https://wacaresfund.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-009', 'WA-INS-009', 'WA Cares Fund — Benefit Structure', 'Eligible workers who have paid premiums for at least 10 years (or 3 of the last 6 years for those 55+) may access a lifetime benefit of $36,500 (indexed to inflation) for long-term care services. Benefits cover services including adult family home, assisted living, home care, home modifications, home-delivered meals, personal emergency response systems, and caregiver support. Benefits are available regardless of age, condition, or income level once eligibility is met.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 50B.04.060; RCW 50B.04.050', 'https://wacaresfund.wa.gov/about-the-wa-cares-fund', 1);

-- Auto Insurance
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-010', 'WA-INS-010', 'Mandatory Auto Liability Insurance', 'Washington requires all vehicle owners to maintain liability insurance with minimum limits of $25,000 bodily injury per person, $50,000 bodily injury per accident, and $10,000 property damage per accident (25/50/10). Proof of insurance must be carried in the vehicle and presented upon request by law enforcement. Driving without insurance is a traffic infraction with fines and potential license suspension. Employers with commercial fleets must ensure all vehicles meet minimum coverage requirements.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 46.30.020; RCW 46.29.090', 'https://www.insurance.wa.gov/auto-insurance', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-011', 'WA-INS-011', 'Uninsured/Underinsured Motorist Coverage', 'Auto insurers in Washington must offer uninsured motorist (UM) and underinsured motorist (UIM) coverage with every policy. The insured may reject UM/UIM coverage in writing but the rejection must be a knowing, affirmative act. Default UM/UIM limits must equal the liability limits unless a lower amount is specifically selected. UIM coverage in Washington is triggered when the at-fault driver''s limits are insufficient to cover damages — Washington follows the "gap" theory for UIM coverage.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 48.22.030', 'https://www.insurance.wa.gov/auto-insurance', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-012', 'WA-INS-012', 'Personal Injury Protection Coverage', 'Washington auto insurers must offer Personal Injury Protection (PIP) coverage with every auto policy. PIP provides no-fault coverage for medical expenses, lost wages, funeral expenses, and loss of services resulting from a motor vehicle accident, regardless of fault. Minimum PIP coverage is $10,000 per person. The insured may reject PIP in writing. PIP benefits are coordinated with other health insurance coverage and are primary to other coverage.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 48.22.085; RCW 48.22.095', 'https://www.insurance.wa.gov/auto-insurance', 1);

-- Health Insurance
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-013', 'WA-INS-013', 'Washington Healthplanfinder — Individual Mandate and Exchange', 'Washington operates a state-based health insurance exchange (Washington Healthplanfinder) under the Affordable Care Act. While Washington does not have an individual mandate penalty, the state provides premium subsidies through the Cascade Care program for individuals up to 250% of the federal poverty level. Small employers (50 or fewer employees) may purchase group plans through the SHOP exchange. All individual and small group plans must cover essential health benefits.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 43.71.020; RCW 48.43.005', 'https://www.wahealthplanfinder.org/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-014', 'WA-INS-014', 'Small Group Health Insurance Requirements', 'Insurers offering small group health plans (2-50 employees) in Washington must guarantee issue to all small employers regardless of health status, use modified community rating (age band no more than 3:1), and cover all essential health benefits. Small group plans may not exclude preexisting conditions, impose annual or lifetime dollar limits on essential health benefits, or discriminate based on health status. Employers must contribute at least 50% of the employee-only premium.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 48.43.005; RCW 48.44.023', 'https://www.insurance.wa.gov/health-insurance', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-015', 'WA-INS-015', 'Cascade Care — Public Option Health Plans', 'Washington''s Cascade Care program (2019) directs the Health Benefit Exchange to offer standardized health plans in the individual market. Beginning 2024, Cascade Care plans must be offered on the exchange in every county. Plans cap provider reimbursement rates and provide state premium subsidies for enrollees up to 250% FPL. Carriers are required to participate if they offer individual market plans in the state. Plans must cover essential health benefits and follow standardized cost-sharing designs.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 43.71.095; SB 5526 (2019)', 'https://www.wahealthplanfinder.org/', 1);

-- Professional Liability
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-016', 'WA-INS-016', 'Professional Liability Insurance — Attorneys', 'While Washington does not mandate malpractice insurance for attorneys, the Washington State Bar Association requires disclosure of malpractice insurance status on annual license renewal. Attorneys without insurance must disclose this to clients in writing at the time of engagement. The Lawyers'' Fund for Client Protection provides limited compensation to clients harmed by dishonest attorney conduct but does not cover negligence.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'APR 26; WSBA Licensing Rules', 'https://www.wsba.org/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-017', 'WA-INS-017', 'Professional Liability — Healthcare Providers', 'Healthcare facilities and providers in Washington must maintain professional liability insurance or provide proof of financial responsibility. Hospitals must maintain coverage of at least $1,000,000 per occurrence. The state provides a voluntary patient compensation program. Medical malpractice claims require a certificate of merit from a qualified expert. Mandatory mediation may be required before trial under certain local court rules.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 7.70.100; RCW 48.43.300', 'https://www.insurance.wa.gov/', 1);

-- Contractor Bond Requirements
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-018', 'WA-INS-018', 'Contractor Surety Bond — General Requirements', 'General contractors must maintain a surety bond of $12,000 filed with L&I. Specialty contractors require a $6,000 bond. Contractors with documented claims may be required to increase bond amounts up to $30,000. The bond protects consumers, employees, and subcontractors from contractor non-performance, non-payment of wages, and non-payment for materials. Bond must remain active throughout the registration period. Cash deposits or irrevocable letters of credit may substitute for surety bonds.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.27.040', 'https://lni.wa.gov/licensing-permits/contractors/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-019', 'WA-INS-019', 'Public Works Performance and Payment Bonds', 'Contractors on public works projects in Washington must furnish a performance bond and a payment bond, each equal to 100% of the contract price for contracts over $150,000. For contracts between $35,000 and $150,000, a retainage bond or other security may substitute. Payment bonds protect subcontractors, laborers, and material suppliers. Performance bonds guarantee project completion. Bond requirements apply to state, county, and municipal public works under RCW 39.08.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 39.08.010; RCW 39.08.030', 'https://app.leg.wa.gov/RCW/default.aspx?cite=39.08', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-020', 'WA-INS-020', 'Commercial Property Insurance — Business Owner Requirements', 'While not mandated by state law, commercial property insurance is effectively required for businesses with mortgaged property (lender requirement), commercial leases (landlord requirement), and government contracts. Washington insurance regulations require insurers to use approved rates, provide coverage explanations, honor the valued policy law for total losses, and give 45 days notice of cancellation or non-renewal for commercial policies.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 48.18.290; RCW 48.18.2901', 'https://www.insurance.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-021', 'WA-INS-021', 'Insurance Policy Cancellation and Non-Renewal Protections', 'Washington provides significant protections against arbitrary insurance cancellation. Insurers must provide written notice of cancellation (20 days for non-payment, 45 days for other reasons). Non-renewal notices must be sent at least 60 days before the policy expiration date. Insurers must state the specific reason for cancellation or non-renewal. Employers may not be cancelled solely for filing workers'' compensation claims. Commercial policyholders have the right to appeal cancellation decisions.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 48.18.290; RCW 48.18.2901', 'https://www.insurance.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-022', 'WA-INS-022', 'Cyber Liability Insurance — Recommended for Data Holders', 'While not mandated by statute, Washington''s broad data breach notification law (RCW 19.255.010), the My Health My Data Act, and the biometric identifier law create significant financial exposure for data breaches. The Attorney General has indicated that failure to carry adequate cyber insurance may be considered evidence of unreasonable data security practices. Businesses collecting personal information, health data, or biometric identifiers should maintain cyber liability coverage including breach response costs.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.255.010; AG Guidance', 'https://www.atg.wa.gov/data-breach-notifications', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-023', 'WA-INS-023', 'Employment Practices Liability Considerations', 'Washington''s employment laws — including the Washington Law Against Discrimination (WLAD), paid sick leave, PFML, and the new non-compete restrictions — create significant employer liability exposure. EPLI coverage addresses claims of wrongful termination, discrimination, sexual harassment, retaliation, and wage/hour violations. While not statutorily required, EPLI is strongly recommended given that Washington allows uncapped emotional distress damages in WLAD claims.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.60; Common Law', 'https://www.insurance.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-024', 'WA-INS-024', 'Directors and Officers Liability Insurance', 'Washington nonprofit corporations and for-profit companies with boards of directors should maintain D&O insurance to protect directors and officers from personal liability for corporate decisions. Under RCW 23B.08.510, a corporation may indemnify directors for expenses if the director acted in good faith and reasonably believed actions were in the corporation''s best interest. D&O insurance supplements statutory indemnification and is often required by investors or lenders.', 'INSURANCE', 'STATE', 'WA', '["CORPORATION","S_CORP","NONPROFIT","LLC"]', '2024-01-01', 'RCW 23B.08.510; RCW 23B.08.560', 'https://app.leg.wa.gov/RCW/default.aspx?cite=23B.08.510', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-ins-025', 'WA-INS-025', 'Commercial General Liability Insurance — Minimum Standards', 'Washington insurers offering commercial general liability policies must comply with the Insurance Commissioner''s standards for policy forms, rates, and claims handling. CGL policies in Washington must clearly define the scope of coverage, exclusions, and conditions. The Insurance Commissioner reviews and approves all rate filings. Businesses contracting with the state or local governments are typically required to carry CGL coverage with minimum limits of $1,000,000 per occurrence and $2,000,000 aggregate.', 'INSURANCE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 48.18.100; RCW 48.19.020', 'https://www.insurance.wa.gov/', 1);

-- ============================================================
-- SECTION 4: ENVIRONMENTAL (25 rules) — wa-env-001 to wa-env-025
-- ============================================================

-- SEPA
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-001', 'WA-ENV-001', 'State Environmental Policy Act — Environmental Review', 'The State Environmental Policy Act (SEPA) requires state and local agencies to consider environmental impacts before approving proposals that may significantly affect the environment. Projects undergo a threshold determination: a Determination of Non-Significance (DNS) for minimal impact, a Mitigated DNS (MDNS) with conditions, or an Environmental Impact Statement (EIS) for significant impacts. SEPA applies to government actions, permits, licenses, and projects involving public funding.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 43.21C.030; WAC 197-11', 'https://ecology.wa.gov/regulations-permits/sepa', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-002', 'WA-ENV-002', 'SEPA Environmental Checklist', 'Project proponents must complete an Environmental Checklist detailing the proposal''s potential impacts on earth, air, water, plants, animals, energy, natural resources, environmental health, land use, transportation, and public services. The lead agency uses this checklist for its threshold determination. Incomplete or inaccurate checklists may delay project review. Categorical exemptions exist for minor projects including single-family residences, minor repairs, and emergency actions under WAC 197-11-800.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'WAC 197-11-315; WAC 197-11-960', 'https://ecology.wa.gov/regulations-permits/sepa/environmental-review', 1);

-- Shoreline Management Act
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-003', 'WA-ENV-003', 'Shoreline Management Act — Substantial Development Permit', 'Development within 200 feet of the ordinary high water mark of shorelines of the state requires a Substantial Development Permit from the local jurisdiction. "Substantial development" means any development with a total cost or fair market value exceeding $7,047 (2024 threshold, adjusted biennially). Permits require consistency with the local Shoreline Master Program and the Shoreline Management Act. Exemptions exist for normal maintenance, emergency construction, and single-family residences on conforming lots.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 90.58.030; RCW 90.58.140', 'https://ecology.wa.gov/water-shorelines/shoreline-coastal-management', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-004', 'WA-ENV-004', 'Shoreline Master Programs — Local Implementation', 'Each city and county with qualifying shorelines must adopt a Shoreline Master Program (SMP) consistent with the Shoreline Management Act guidelines. SMPs classify shoreline environments (natural, rural conservancy, shoreline residential, urban conservancy, high intensity) and establish permitted uses, setbacks, and development standards for each. SMPs must be updated periodically and approved by the Department of Ecology. Development must comply with the applicable SMP.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 90.58.080; WAC 173-26', 'https://ecology.wa.gov/water-shorelines/shoreline-coastal-management/shoreline-master-programs', 1);

-- Growth Management Act
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-005', 'WA-ENV-005', 'Growth Management Act — Comprehensive Planning', 'The Growth Management Act (GMA) requires the fastest-growing counties and cities in Washington to adopt comprehensive plans and development regulations. Plans must include land use, housing, capital facilities, utilities, and transportation elements. Plans must designate Urban Growth Areas to concentrate development and protect rural lands, agricultural lands, forest lands, and mineral resource lands. Comprehensive plans must be updated every 10 years (8 years for most counties under 2024 amendments).', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 36.70A.040; RCW 36.70A.070', 'https://www.commerce.wa.gov/serving-communities/growth-management/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-006', 'WA-ENV-006', 'Growth Management Act — Critical Areas Protection', 'Counties and cities must designate and protect critical areas including wetlands, areas with critical recharging effect on aquifers, fish and wildlife habitat conservation areas, frequently flooded areas, and geologically hazardous areas. Development in or near critical areas requires compliance with critical areas ordinances that establish buffers, mitigation requirements, and development standards. Best available science must be included in the development of critical area policies and regulations.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 36.70A.060; RCW 36.70A.172', 'https://www.commerce.wa.gov/serving-communities/growth-management/critical-areas/', 1);

-- Ecology Permits
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-007', 'WA-ENV-007', 'Air Quality Permit — New Source Review', 'Facilities that emit air contaminants must obtain an air quality permit from the Department of Ecology or the local clean air agency. New Source Review applies to new or modified sources of air pollution. Permits specify emission limits, monitoring requirements, and reporting obligations. Major sources (exceeding Prevention of Significant Deterioration thresholds) require federal Title V operating permits. Emission fees are assessed annually based on tons of pollutants emitted.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 70A.15.2210; WAC 173-400', 'https://ecology.wa.gov/regulations-permits/permits-certifications/air-quality-permits', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-008', 'WA-ENV-008', 'Water Quality — State Waste Discharge Permit', 'Facilities discharging waste materials to waters of the state (surface water, ground water, or municipal sewer systems) must obtain a State Waste Discharge Permit from Ecology. Permits set effluent limitations, monitoring requirements, and reporting schedules consistent with state water quality standards under WAC 173-200 (groundwater) and WAC 173-201A (surface water). Unpermitted discharges are subject to penalties up to $10,000 per day per violation.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 90.48.160; WAC 173-216', 'https://ecology.wa.gov/regulations-permits/permits-certifications/water-quality-permits', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-009', 'WA-ENV-009', 'Dangerous Waste Management', 'Businesses generating, transporting, treating, storing, or disposing of dangerous waste must comply with the Dangerous Waste Regulations under WAC 173-303. Washington''s dangerous waste rules are broader than federal RCRA and include state-only designations. Generators must obtain an EPA/state identification number, characterize waste, use proper containers and labeling, maintain records, and submit annual reports. Treatment, storage, and disposal facilities require permits from Ecology.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 70A.300.020; WAC 173-303', 'https://ecology.wa.gov/regulations-permits/guidance-technical-assistance/dangerous-waste-guidance', 1);

-- NPDES Permits
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-010', 'WA-ENV-010', 'NPDES Permit — Point Source Discharge', 'Facilities discharging pollutants from a point source to surface waters of the state must obtain a National Pollutant Discharge Elimination System (NPDES) permit from Ecology. NPDES permits establish technology-based effluent limits, water quality-based limits, monitoring requirements, and compliance schedules. General NPDES permits are available for categories of similar dischargers (sand and gravel, stormwater). Individual permits are required for complex or unique discharges. Permit term is five years with renewal required.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 90.48.162; WAC 173-220', 'https://ecology.wa.gov/regulations-permits/permits-certifications/water-quality-permits', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-011', 'WA-ENV-011', 'Construction Stormwater General Permit', 'Construction activities disturbing one or more acres of land (or part of a larger common plan of development) must obtain coverage under the Construction Stormwater General Permit from Ecology. Permittees must prepare and implement a Stormwater Pollution Prevention Plan (SWPPP), install best management practices to control erosion and sediment, conduct regular site inspections, and submit discharge monitoring reports. Turbidity limits apply to site discharge. Permit must be obtained before ground disturbance.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 173-226; Construction Stormwater General Permit', 'https://ecology.wa.gov/regulations-permits/permits-certifications/stormwater-general-permits', 1);

-- Puget Sound Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-012', 'WA-ENV-012', 'Puget Sound Water Quality Protection', 'The Puget Sound Partnership leads the state''s effort to restore and protect Puget Sound by 2050. Businesses operating in the Puget Sound watershed are subject to enhanced environmental requirements including stricter stormwater treatment standards, copper-free brake pad requirements, and restrictions on toxic chemicals. Local jurisdictions in the Puget Sound basin must adopt more stringent stormwater management manuals. Ecology applies enhanced water quality standards to discharges affecting Puget Sound waters.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 90.71.005; RCW 90.71.300', 'https://www.psp.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-013', 'WA-ENV-013', 'Puget Sound Nutrient General Permit', 'Domestic wastewater treatment plants discharging to Puget Sound or its tributaries must comply with the Puget Sound Nutrient General Permit requiring phased reduction of nitrogen discharges. This permit addresses the nutrient pollution causing low dissolved oxygen levels in Puget Sound. Facilities must monitor and report nitrogen levels, develop optimization plans, and meet interim and final nitrogen reduction milestones. Full compliance expected by 2040 with interim targets beginning 2027.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","NONPROFIT"]', '2024-01-01', 'WAC 173-226; Ecology Puget Sound Nutrient General Permit', 'https://ecology.wa.gov/water-shorelines/puget-sound/nutrient-reduction', 1);

-- Climate Commitment Act
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-014', 'WA-ENV-014', 'Climate Commitment Act — Cap-and-Invest Program', 'Washington''s Climate Commitment Act (2021) established a cap-and-invest program beginning January 2023. Covered entities emitting 25,000 metric tons or more of CO2 equivalent annually must obtain emission allowances through quarterly auctions or the secondary market. Allowance prices have exceeded $50/ton. Revenue funds clean energy, transportation electrification, and climate resilience. Covered sectors include electricity generation, petroleum product suppliers, natural gas distributors, and large industrial facilities.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 70A.65.010; RCW 70A.65.060', 'https://ecology.wa.gov/air-climate/climate-commitment-act', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-015', 'WA-ENV-015', 'Climate Commitment Act — Emission Reporting', 'Facilities emitting 10,000 metric tons or more of greenhouse gases annually must report emissions to Ecology. Covered entities (25,000+ metric tons) must additionally surrender allowances equal to their emissions. Reports must follow EPA Mandatory Greenhouse Gas Reporting Rule methods or Ecology-approved protocols. Third-party verification required for covered entities. Reports due annually by March 31 for the preceding calendar year''s emissions. Non-compliance results in penalties of $50,000 per day plus four times the value of unaccounted allowances.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 70A.15.2200; WAC 173-441', 'https://ecology.wa.gov/air-climate/climate-commitment-act/reporting', 1);

-- Clean Energy Transformation Act (CETA)
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-016', 'WA-ENV-016', 'Clean Energy Transformation Act — 100% Clean Electricity by 2045', 'The Clean Energy Transformation Act (CETA) requires all electric utilities in Washington to be greenhouse gas neutral by 2030 and supply 100% clean electricity by 2045. By 2030, utilities must use renewable energy or purchase renewable energy credits for 80% of retail sales, with the remaining 20% offset by alternative compliance options. Utilities must submit clean energy implementation plans every four years, including specific and actionable steps, to the UTC or governing body. Integrated resource plans must address CETA targets.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","NONPROFIT"]', '2024-01-01', 'RCW 19.405.040; RCW 19.405.050', 'https://www.commerce.wa.gov/growing-the-economy/energy/ceta/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-017', 'WA-ENV-017', 'CETA — Energy Transformation Equity Requirements', 'CETA requires utilities to ensure that the benefits and burdens of the clean energy transformation are equitably distributed. Utilities must identify highly impacted communities and vulnerable populations and develop strategies to reduce energy burden (spending more than 6% of household income on energy) in those communities. Clean energy plans must include public participation, address cumulative impacts, and dedicate a portion of energy efficiency and demand response spending to low-income customers.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","NONPROFIT"]', '2024-01-01', 'RCW 19.405.040(8); RCW 19.405.010', 'https://www.commerce.wa.gov/growing-the-economy/energy/ceta/', 1);

-- Model Toxics Control Act
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-018', 'WA-ENV-018', 'Model Toxics Control Act — Cleanup Standards', 'The Model Toxics Control Act (MTCA) is Washington''s primary environmental cleanup law. Property owners and operators who release hazardous substances are strictly liable for cleanup costs. Ecology maintains a Confirmed and Suspected Contaminated Sites list. Cleanup standards are set under WAC 173-340 and require remediation to protect human health and the environment. Voluntary cleanup program available for parties who self-initiate investigation and cleanup with Ecology oversight. Prospective purchaser agreements available for brownfield redevelopment.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 70A.305.010; WAC 173-340', 'https://ecology.wa.gov/spills-cleanup/contamination-cleanup', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-019', 'WA-ENV-019', 'Model Toxics Control Act — Hazardous Substance Tax', 'MTCA is funded by a hazardous substance tax on the wholesale value of certain substances including petroleum products, pesticides, and chemicals. The tax rate is 0.7% of the wholesale value. Revenue funds the Model Toxics Control Operating Account (for cleanup), Capital Account, and Stormwater Account. Businesses that manufacture, import, or first possess hazardous substances in Washington must register and pay the tax quarterly to the Department of Revenue.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 82.21.030; RCW 82.21.040', 'https://dor.wa.gov/taxes-rates/other-taxes/hazardous-substance-tax', 1);

-- Oil Spill Prevention
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-020', 'WA-ENV-020', 'Oil Spill Prevention and Response', 'Facilities that store, transfer, or transport oil in Washington must comply with the state oil spill prevention program. Tank vessels, cargo vessels, and covered vessels must carry approved oil spill contingency plans. Facilities with storage capacity of more than 10,000 gallons must prepare facility oil spill prevention and contingency plans. The Oil Spill Administration collects per-barrel fees on oil received at facilities. Spills must be immediately reported to Ecology''s spill hotline.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 88.46.040; RCW 90.56.210', 'https://ecology.wa.gov/spills-cleanup/spills/spill-prevention', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-021', 'WA-ENV-021', 'Underground Storage Tank Compliance', 'Owners and operators of underground storage tanks (USTs) containing petroleum or hazardous substances must register with Ecology, carry financial responsibility ($1 million per occurrence, $2 million aggregate), implement leak detection and spill/overfill prevention, and comply with EPA technical requirements. USTs must be upgraded or replaced to meet current standards including secondary containment, corrosion protection, and leak detection. The Pollution Liability Insurance Agency offers a trust fund for cleanup of petroleum UST releases.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 70A.355.020; WAC 173-360A', 'https://ecology.wa.gov/regulations-permits/guidance-technical-assistance/underground-storage-tank-guidance', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-022', 'WA-ENV-022', 'Water Rights and Water Use Permits', 'Appropriation of surface water or groundwater in Washington requires a water right permit from Ecology. Permit-exempt wells are allowed for domestic use (up to 5,000 gallons per day), stock watering, and industrial purposes (limited). New water rights are subject to availability and may be curtailed during periods of low flow. Water rights are property rights subject to the prior appropriation doctrine ("first in time, first in right"). Transferring or changing the purpose, place, or quantity of a water right requires Ecology approval.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 90.03.250; RCW 90.44.050', 'https://ecology.wa.gov/water-shorelines/water-supply/water-rights', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-023', 'WA-ENV-023', 'Hydraulic Project Approval — Fish Habitat', 'Any construction or activity that uses, diverts, obstructs, or changes the natural flow or bed of any state waters requires a Hydraulic Project Approval (HPA) from the Washington Department of Fish and Wildlife. HPAs include conditions to protect fish life and habitat, including work window restrictions (when construction may occur), mitigation measures, and monitoring requirements. Emergency HPAs available for urgent situations. Violations may result in civil penalties up to $100 per day per violation.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 77.55.021; WAC 220-660', 'https://wdfw.wa.gov/licenses/environmental/hpa', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-024', 'WA-ENV-024', 'Toxic Pollution Prevention — PFAS Restrictions', 'Washington has enacted some of the nation''s strongest restrictions on per- and polyfluoroalkyl substances (PFAS). Beginning 2025, PFAS are prohibited in food packaging, cosmetics, and firefighting foam. Ecology is authorized to restrict PFAS in additional product categories where safer alternatives exist. Manufacturers must notify Ecology before selling products containing intentionally added PFAS. The Chemical Action Plan for PFAS guides additional regulatory actions.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 70A.350.020; SB 5432 (2023)', 'https://ecology.wa.gov/waste-toxics/reducing-toxic-chemicals/addressing-priority-toxic-chemicals/pfas', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-env-025', 'WA-ENV-025', 'Solid Waste Management and Recycling Requirements', 'Businesses generating solid waste must comply with Washington''s solid waste management hierarchy: reduce, reuse, recycle, then recover energy, then landfill. Cities and counties must adopt comprehensive solid waste management plans. The Organic Materials Management Act requires businesses generating at least 8 cubic yards of organic waste per week to arrange for composting or organic waste collection (phased implementation through 2027). Producers of certain packaging and paper products will be subject to extended producer responsibility requirements beginning 2027.', 'ENVIRONMENTAL', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 70A.205.005; RCW 70A.205.045', 'https://ecology.wa.gov/waste-toxics/reducing-recycling-waste', 1);

-- ============================================================
-- SECTION 5: CONSUMER PROTECTION (20 rules) — wa-cons-001 to wa-cons-020
-- ============================================================

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-001', 'WA-CONS-001', 'Consumer Protection Act — Unfair or Deceptive Practices', 'The Washington Consumer Protection Act (CPA) prohibits unfair or deceptive acts or practices in trade or commerce. Unlike most states, Washington''s CPA does not require proof of intent — a business may be liable for unfair practices even without knowledge. The CPA provides a private right of action with treble damages (up to $25,000), attorney fees, and injunctive relief. The Attorney General may seek civil penalties of up to $7,500 per violation. The CPA is the primary enforcement vehicle for many other consumer statutes.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.86.020; RCW 19.86.090', 'https://www.atg.wa.gov/consumer-protection', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-002', 'WA-CONS-002', 'Consumer Protection Act — Per Se Violations', 'Certain practices are declared per se violations of the CPA, meaning the plaintiff need not prove the elements of unfairness or deception. Per se violations include violations of specific consumer statutes such as the data breach notification law (RCW 19.255), student data privacy (RCW 28A.604), spam protections (RCW 19.190), and commercial telephone solicitation rules (RCW 19.158). A violation of any statute declared to be a CPA violation automatically satisfies the unfair or deceptive act element.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.86.020; Various Per Se Statutes', 'https://www.atg.wa.gov/consumer-protection', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-003', 'WA-CONS-003', 'Lemon Law — New Motor Vehicle Warranties', 'Washington''s Lemon Law provides remedies for purchasers or lessees of new motor vehicles with substantial defects that cannot be repaired after a reasonable number of attempts. A "reasonable number of attempts" is presumed after four repair attempts for the same defect, or 30 or more cumulative business days out of service. If the manufacturer cannot repair the defect, the consumer is entitled to a replacement vehicle or full refund less a reasonable allowance for use. Claims must be made within 24 months or 24,000 miles of original delivery.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.118.021; RCW 19.118.041', 'https://www.atg.wa.gov/lemon-law', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-004', 'WA-CONS-004', 'Lemon Law — Used Car Warranty Requirements', 'Washington''s Used Car Lemon Law requires dealers to provide an express warranty on used vehicles sold for more than $1,000 (excluding vehicles with 100,000+ miles). Warranty coverage: vehicles with under 40,000 miles get a 90-day/3,750-mile warranty covering the engine, transmission, and drivetrain. Vehicles between 40,000-80,000 miles get 60-day/2,500-mile coverage. Vehicles between 80,000-100,000 miles get 30-day/1,250-mile coverage. Dealers must provide a written warranty document at the time of sale.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 46.70.130; WAC 308-56A-420', 'https://www.atg.wa.gov/lemon-law', 1);

-- Debt Collection
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-005', 'WA-CONS-005', 'Debt Collection Licensing and Practices', 'Collection agencies operating in Washington must be licensed by the Department of Licensing and post a surety bond of $10,000 to $30,000 depending on collection volume. Debt collectors may not use threats of violence, obscene language, or misrepresentation. Collectors must send written validation notice within 5 days of initial contact. Collectors may not contact debtors at inconvenient times (before 8 a.m. or after 9 p.m.) or at their workplace if the employer prohibits such calls.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 19.16.100; RCW 19.16.250', 'https://www.dol.wa.gov/business/collectionagencies/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-006', 'WA-CONS-006', 'Medical Debt Collection Protections', 'Washington provides enhanced protections for medical debt. Hospitals must screen patients for charity care eligibility before pursuing collections. Patients at or below 300% of the federal poverty level qualify for free or reduced care at hospitals. Medical debt may not be reported to credit bureaus for 365 days after first billing. Wage garnishment for medical debt is limited. Health care facilities must provide itemized billing statements and offer reasonable payment plans before initiating collection actions.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 70.170.060; RCW 19.16.250', 'https://www.atg.wa.gov/medical-debt', 1);

-- Auto Dealer Practices
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-007', 'WA-CONS-007', 'Auto Dealer Unfair Practices', 'Washington prohibits numerous auto dealer practices including yo-yo financing (delivering a vehicle and later claiming financing fell through to renegotiate terms), failure to disclose material vehicle history, packing payments with unwanted products, advertising vehicles not available at the advertised price, and charging documentation fees exceeding $200. Dealers must provide a Buyer''s Guide and comply with the FTC Used Car Rule. Violations are per se CPA violations with treble damages and attorney fees.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 46.70.180; WAC 308-56A', 'https://www.atg.wa.gov/buying-car', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-008', 'WA-CONS-008', 'Motor Vehicle Dealer Documentation Fee Cap', 'Motor vehicle dealers in Washington may charge a negotiable documentation fee for processing paperwork but must clearly disclose the fee. As of 2024, the fee must be reasonable and applied uniformly to all buyers. The dealer must post the documentation fee in a conspicuous location in the dealership. Adding undisclosed fees, charging different documentation fees to different customers, or misrepresenting government fees as dealer charges are violations of RCW 46.70.180.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 46.70.180(12); WAC 308-56A', 'https://www.atg.wa.gov/buying-car', 1);

-- Gift Card Protections
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-009', 'WA-CONS-009', 'Gift Card and Certificate Protections', 'Gift certificates and gift cards sold in Washington may not have an expiration date and may not be subject to service fees, dormancy fees, or inactivity fees. If the balance on a gift card falls below $5, the holder may request a cash refund from the issuer. Sellers must maintain records sufficient to honor outstanding gift cards. These protections do not apply to prepaid calling cards, promotional cards given for free, or cards redeemable at multiple unaffiliated merchants.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.240.020; RCW 19.240.030', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.240', 1);

-- Price Gouging
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-010', 'WA-CONS-010', 'Price Gouging During Emergencies', 'During a declared state of emergency, it is unlawful to sell essential goods or services at an unconscionably excessive price. The Attorney General considers whether the price is more than 10% above the pre-emergency price, whether the increase is attributable to increased supplier costs, and whether the seller''s profit margin is significantly greater than pre-emergency margins. Essential goods include food, water, fuel, medicine, building materials, and emergency supplies. Violations are per se CPA violations.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.86.020; AG Emergency Price Gouging Authority', 'https://www.atg.wa.gov/price-gouging', 1);

-- Telephone Solicitation
INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-011', 'WA-CONS-011', 'Telephone Solicitation Registration and Practices', 'Commercial telephone solicitors must register with the Department of Licensing and post a $10,000 surety bond. Solicitation calls may only be made between 8 a.m. and 8 p.m. Solicitors must identify themselves, the company, and the purpose of the call at the beginning. No call may be made to any number on the federal Do Not Call Registry or that has been identified by the consumer as off-limits. Automated calls (robocalls) for commercial purposes require prior express consent. Violations subject to $1,000 per call penalties.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.158.020; RCW 19.158.110', 'https://www.dol.wa.gov/business/telephonesolicitors/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-012', 'WA-CONS-012', 'Automatic Renewal and Continuous Service Protections', 'Businesses offering automatic renewal or continuous service offers to Washington consumers must clearly and conspicuously disclose the automatic renewal terms, cancellation policy, and recurring charges before the consumer agrees. Consumers must affirmatively consent to the automatic renewal. Businesses must provide a simple mechanism for cancellation, including an online cancellation option if the service was purchased online. Failure to comply makes the automatic renewal provision unenforceable and is a CPA violation.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.86.020; FTC Guidelines', 'https://www.atg.wa.gov/consumer-protection', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-013', 'WA-CONS-013', 'Home Improvement Contract Requirements', 'Home improvement contracts exceeding $1,000 must be in writing and include the contractor''s registration number, start and completion dates, description of work, total price, payment schedule, and a notice of the homeowner''s right to cancel within three business days for door-to-door sales. Contractors must not demand more than 10% of the contract price as a down payment or collect payment for materials not yet delivered. Change orders must be in writing and signed by both parties.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.27.114; RCW 19.86.020', 'https://lni.wa.gov/licensing-permits/contractors/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-014', 'WA-CONS-014', 'Refund and Return Policy Disclosure', 'Washington retailers must clearly post their refund, return, exchange, and credit policies. If no policy is posted, consumers have the right to a full refund or exchange within 30 days of purchase with proof of purchase. Policies must be displayed at each register or point of sale and on websites for online sales. Restocking fees must be clearly disclosed before the purchase. A "no returns" or "all sales final" policy must be conspicuously posted to be enforceable.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.86.020; AG Consumer Guidelines', 'https://www.atg.wa.gov/consumer-protection', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-015', 'WA-CONS-015', 'Truth in Advertising — Bait and Switch', 'Washington prohibits bait-and-switch advertising — advertising goods or services with no genuine intent to sell them at the advertised price for the purpose of luring consumers to purchase different, typically more expensive, goods or services. Advertisements must clearly disclose material limitations including quantity, size, and availability. Advertising an item as "free" when the consumer must purchase another item is subject to disclosure requirements. Violations are per se unfair or deceptive under the CPA.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.86.020; WAC 284-30-330', 'https://www.atg.wa.gov/consumer-protection', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-016', 'WA-CONS-016', 'Charitable Solicitations Registration', 'Charitable organizations soliciting donations in Washington must register with the Secretary of State''s Charities Program before soliciting. Registration requires financial statements, fundraising methods, and identification of paid solicitors. Commercial fundraisers and fundraising counsel must also register and post a $25,000 surety bond. Annual renewal and reporting required. Solicitations must clearly disclose the name of the charity and the percentage of contributions going to charitable purposes. Deceptive solicitation is a CPA violation.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["NONPROFIT","LLC","CORPORATION"]', '2024-01-01', 'RCW 19.09.020; RCW 19.09.065', 'https://www.sos.wa.gov/charities', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-017', 'WA-CONS-017', 'Data Breach Notification — Consumer-Facing Requirements', 'When a data breach affects Washington residents, the breached entity must provide clear, plain-language notification to affected consumers. Notification must describe the breach, the types of personal information compromised, what the business is doing to protect affected individuals (such as free credit monitoring), a toll-free phone number for inquiries, and contact information for the three major credit bureaus. For breaches involving Social Security numbers, the business should offer at least 12 months of credit monitoring at no cost.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.255.010', 'https://www.atg.wa.gov/data-breach-notifications', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-018', 'WA-CONS-018', 'Real Estate Advertising Disclosures', 'Real estate advertisements in Washington must include the name of the brokerage firm under which the broker is licensed. Advertising that implies guaranteed returns, conceals material facts, or misrepresents property conditions violates the CPA. For-sale-by-owner advertisements must not imply broker involvement. All claims about property features, proximity to amenities, or investment potential must be accurate and verifiable. Online listings must be promptly updated when a property is sold or the terms change.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 18.85.361; WAC 308-124C', 'https://www.dol.wa.gov/business/realestate/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-019', 'WA-CONS-019', 'Online Marketplace Transparency', 'Washington requires high-volume third-party sellers on online marketplaces to provide their legal name, physical address, working contact information (phone and email), and state-issued tax number. Online marketplaces must verify this information and make it available to consumers. This applies to sellers making 200+ sales or $5,000+ in gross revenue annually on a marketplace platform. Failure to comply is a per se CPA violation. Sellers may request address redaction if they demonstrate personal safety concerns.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 19.86.020; INFORM Consumers Act (State)', 'https://www.atg.wa.gov/consumer-protection', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cons-020', 'WA-CONS-020', 'Consumer Lease Disclosure Requirements', 'Consumer leases for personal property (vehicles, equipment) must comply with disclosure requirements including total amount due at lease signing, number and amounts of periodic payments, total of all payments, purchase option terms, excessive wear and use standards, and early termination penalties. Lease advertisements must disclose all material terms if any specific payment amount is advertised. Gap insurance offering requirements apply to auto leases. Violations enforceable under the CPA and federal Consumer Leasing Act.', 'CONSUMER_PROTECTION', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 63.10.020; 15 USC 1667', 'https://www.atg.wa.gov/consumer-protection', 1);

-- ============================================================
-- SECTION 6: HEALTHCARE (15 rules) — wa-health-001 to wa-health-015
-- ============================================================

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-001', 'WA-HEALTH-001', 'Certificate of Need — Healthcare Facility Construction', 'Washington requires a Certificate of Need (CON) from the Department of Health before constructing, expanding, or modernizing certain healthcare facilities or services. Covered activities include new hospitals, nursing homes, ambulatory surgery centers, certain capital expenditures exceeding $3.6 million, and new services such as organ transplant, cardiac surgery, or neonatal intensive care. The CON process evaluates community need, financial feasibility, and quality of care standards.', 'HEALTHCARE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","NONPROFIT"]', '2024-01-01', 'RCW 70.38.015; RCW 70.38.105', 'https://doh.wa.gov/licenses-permits-and-certificates/facilities-702/certificate-need', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-002', 'WA-HEALTH-002', 'Hospital Charity Care Requirements', 'Washington hospitals must provide charity care to patients who lack insurance or are underinsured and have income at or below 300% of the federal poverty level (FPL). Patients at or below 100% FPL receive full charity care (100% write-off). Patients between 100-200% FPL receive partial charity care with sliding scale discounts. Hospitals must screen all patients for charity care eligibility before initiating collection actions. Hospitals must report charity care data annually to the Department of Health.', 'HEALTHCARE', 'STATE', 'WA', '["CORPORATION","NONPROFIT","LLC"]', '2024-01-01', 'RCW 70.170.060; WAC 246-453', 'https://doh.wa.gov/data-statistical-reports/healthcare-washington/hospital-financial-data/charity-care', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-003', 'WA-HEALTH-003', 'Balance Billing Protection Act — Surprise Billing', 'Washington''s Balance Billing Protection Act (effective 2019) protects patients from surprise medical bills when they receive emergency services or non-emergency services at an in-network facility from an out-of-network provider without prior notice and consent. Out-of-network providers may not balance bill patients and must accept the health plan''s allowed amount or negotiate through an independent dispute resolution process. Patients are only responsible for in-network cost-sharing amounts.', 'HEALTHCARE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 48.49.020; RCW 48.49.030', 'https://www.insurance.wa.gov/balance-billing-protection-act', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-004', 'WA-HEALTH-004', 'Balance Billing — Prior Consent Exception', 'An out-of-network provider may balance bill a patient only if: the provider gave written notice at least 72 hours before the appointment that the provider is out-of-network and the estimated charges, the patient gave informed consent in writing agreeing to the potential balance bill, the service was non-emergency, and the patient had a reasonable opportunity to seek care from an in-network provider. Emergency services are never subject to balance billing regardless of consent.', 'HEALTHCARE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 48.49.020(4)', 'https://www.insurance.wa.gov/balance-billing-protection-act', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-005', 'WA-HEALTH-005', 'Telehealth Parity — Coverage and Reimbursement', 'Washington requires health insurers to cover healthcare services delivered via telemedicine on the same basis as in-person services. Insurers may not impose additional requirements on telehealth that are not imposed on in-person services (such as requiring an in-person visit first). Audio-only telehealth must be covered when clinically appropriate. Originating site requirements are broadly defined to include the patient''s home. Reimbursement rates for telehealth must be at least equal to in-person rates.', 'HEALTHCARE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 48.43.735; RCW 74.09.325', 'https://app.leg.wa.gov/RCW/default.aspx?cite=48.43.735', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-006', 'WA-HEALTH-006', 'Behavioral Health Integration Requirements', 'Washington law requires the integration of behavioral health (mental health and substance use disorder) services with physical health care. Apple Health (Medicaid) managed care organizations must provide integrated managed care covering both physical and behavioral health. The Health Care Authority oversees behavioral health integration. Licensed behavioral health agencies must comply with WAC 246-341 standards for staffing, treatment planning, and client rights. Parity in coverage between behavioral and physical health is mandated.', 'HEALTHCARE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","NONPROFIT"]', '2024-01-01', 'RCW 71.24.045; WAC 246-341', 'https://www.hca.wa.gov/about-hca/behavioral-health-recovery', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-007', 'WA-HEALTH-007', 'My Health My Data Act — Healthcare Facility Obligations', 'Healthcare facilities not covered by HIPAA (or collecting health data outside HIPAA-covered activities) must comply with the My Health My Data Act. This includes health apps used by facilities, patient-facing portals collecting data beyond treatment purposes, wellness programs, and any consumer health data collected for marketing or analytics. Facilities must obtain separate consent for each category of health data use, maintain health data privacy policies, honor deletion requests, and never sell health data without explicit authorization.', 'HEALTHCARE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 19.373.030; RCW 19.373.050', 'https://app.leg.wa.gov/RCW/default.aspx?cite=19.373', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-008', 'WA-HEALTH-008', 'Reproductive Health Shield Law', 'Washington''s Shield Law (2023) protects individuals seeking or providing lawful reproductive healthcare in Washington from out-of-state legal actions. The law prohibits state agencies and courts from cooperating with out-of-state investigations targeting reproductive healthcare, prevents extradition for lawful reproductive healthcare activities, bars health plans from disclosing reproductive healthcare information to out-of-state entities, and protects healthcare providers from license discipline based on out-of-state laws criminalizing reproductive care.', 'HEALTHCARE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 7.115.010; SB 5489 (2023)', 'https://app.leg.wa.gov/RCW/default.aspx?cite=7.115', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-009', 'WA-HEALTH-009', 'Gender-Affirming Care Shield Law', 'Washington law protects individuals seeking or providing gender-affirming care from out-of-state legal actions. Healthcare providers may not be subject to discipline, loss of license, or civil or criminal liability for providing gender-affirming care that is lawful in Washington. State agencies may not provide information about individuals seeking gender-affirming care in response to out-of-state subpoenas or requests. Health insurers must cover gender-affirming care as medically necessary.', 'HEALTHCARE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 7.115.010; SB 5599 (2023)', 'https://app.leg.wa.gov/RCW/default.aspx?cite=7.115', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-010', 'WA-HEALTH-010', 'Healthcare Price Transparency', 'Washington hospitals must post a machine-readable file of standard charges for all items and services, including DRG-level and CPT-level pricing, negotiated rates with each insurer, discounted cash prices, and gross charges. The Hospital Price Transparency Act requires public access to pricing data and reporting to the Health Care Authority. Beginning 2026, enhanced transparency requirements mandate disclosure of total expected costs for shoppable services to patients upon request within 2 business days.', 'HEALTHCARE', 'STATE', 'WA', '["CORPORATION","NONPROFIT","LLC"]', '2024-01-01', 'RCW 70.01.040; Federal 45 CFR 180', 'https://doh.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-011', 'WA-HEALTH-011', 'Healthcare Worker Staffing Standards', 'Washington enacted nurse staffing standards requiring hospitals to establish staffing committees (50% direct-care nurses) that develop staffing plans with specific nurse-to-patient ratios. Hospitals must publicly report staffing levels and may not require overtime except in emergencies. Violations reported to the Department of Health. Hospitals must maintain records of actual staffing against the plan. Meal and rest break requirements apply to nurses and healthcare technicians with no possibility of waiver during shifts.', 'HEALTHCARE', 'STATE', 'WA', '["CORPORATION","NONPROFIT","LLC"]', '2024-01-01', 'RCW 70.41.420; SB 5236 (2023)', 'https://doh.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-012', 'WA-HEALTH-012', 'Healthcare Entity Material Change Transactions', 'Healthcare entities (hospitals, hospital systems, provider organizations) must provide 60 days advance notice to the Attorney General before completing material change transactions including mergers, acquisitions, or affiliations. The AG reviews transactions for impact on healthcare access, cost, quality, and equity. For transactions involving entities with combined revenue over $10 million, the AG may approve, approve with conditions, or reject the transaction. Failure to provide notice may result in injunction and civil penalties.', 'HEALTHCARE', 'STATE', 'WA', '["CORPORATION","NONPROFIT","LLC"]', '2024-01-01', 'RCW 19.390.030; SB 5241 (2023)', 'https://www.atg.wa.gov/healthcare-transactions', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-013', 'WA-HEALTH-013', 'Prescription Drug Affordability Board', 'Washington established a Prescription Drug Affordability Board to identify drugs with unaffordable costs and set upper payment limits. The board reviews drugs with wholesale acquisition cost increases of 20%+ over one year or 50%+ over three years, new drugs priced over $60,000 annually, and biosimilars priced within 15% of the reference biologic. Upper payment limits apply to state-purchased drugs and may be extended to commercial markets. Manufacturers must report price increases to the board.', 'HEALTHCARE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 70.405.010; SB 5532 (2023)', 'https://www.hca.wa.gov/about-hca/programs-and-initiatives/prescription-drug-affordability', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-014', 'WA-HEALTH-014', 'Informed Consent for Medical Treatment', 'Washington''s informed consent law requires healthcare providers to disclose the nature of the proposed treatment, material risks and alternatives, the probability of success, and the risks of no treatment. Consent must be obtained from the patient or authorized representative before any procedure. Written consent is required for surgical procedures. Failure to obtain informed consent may constitute medical negligence. Special rules apply for minors, emergency situations, and patients lacking capacity.', 'HEALTHCARE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 7.70.050; RCW 7.70.060', 'https://app.leg.wa.gov/RCW/default.aspx?cite=7.70.050', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-health-015', 'WA-HEALTH-015', 'Behavioral Health Emergency Involuntary Treatment', 'Washington''s Involuntary Treatment Act (ITA) governs involuntary commitment for mental health or substance use disorders. Initial detention (up to 120 hours) requires probable cause that the person is a danger to self, others, or gravely disabled. Petitions for 14-day commitment require a judicial hearing with right to counsel. 90-day and 180-day recommitment available with progressively higher evidentiary standards. Designated crisis responders evaluate and file petitions. All patients retain rights to communicate, refuse medication (with exceptions), and petition for release.', 'HEALTHCARE', 'STATE', 'WA', '["CORPORATION","NONPROFIT","LLC"]', '2024-01-01', 'RCW 71.05.150; RCW 71.05.240', 'https://app.leg.wa.gov/RCW/default.aspx?cite=71.05', 1);

-- ============================================================
-- SECTION 7: REAL ESTATE (15 rules) — wa-real-001 to wa-real-015
-- ============================================================

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-001', 'WA-REAL-001', 'Residential Landlord-Tenant Act — Core Tenant Rights', 'The Residential Landlord-Tenant Act (RLTA) governs most residential rental relationships in Washington. Landlords must maintain habitable premises including structural integrity, plumbing, heating, hot water, electricity, and pest control. Tenants have the right to organize, withhold rent for uninhabitable conditions (after proper notice), and repair-and-deduct for minor issues (up to two months'' rent per year). Landlords must provide a written rental agreement for tenancies exceeding 12 months.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 59.18.060; RCW 59.18.070', 'https://www.atg.wa.gov/landlord-tenant', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-002', 'WA-REAL-002', 'Just Cause Eviction — Statewide Requirement', 'Washington enacted statewide just cause eviction protections in 2021 (SB 5160). Landlords may only terminate a month-to-month tenancy for one of the enumerated just causes including non-payment of rent, material lease violation, nuisance, substantial renovation requiring vacancy, owner personal use, or demolition. Landlords must provide written notice specifying the cause. For non-payment, landlords must provide a 14-day pay-or-vacate notice. No-cause terminations are prohibited for all residential tenancies.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 59.18.650; SB 5160 (2021)', 'https://www.atg.wa.gov/landlord-tenant', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-003', 'WA-REAL-003', 'Rent Increase Notice — 60 Days Required', 'Landlords must provide at least 60 days'' written notice before any rent increase for month-to-month tenancies. For subsidized housing, 30 days'' notice is required. Washington does not impose rent caps or limits on the amount of rent increases, but the 60-day notice is mandatory. Rent increases during a fixed-term lease are only permitted if the lease specifically allows it. Rent increases that are retaliatory (within 90 days of a tenant complaint) or discriminatory are prohibited.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 59.18.140; SB 5160 (2021)', 'https://www.atg.wa.gov/landlord-tenant', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-004', 'WA-REAL-004', 'Security Deposit Limits and Requirements', 'Washington does not cap security deposit amounts but imposes strict handling requirements. Deposits must be placed in a trust account at a bank or escrow company and the landlord must provide the name and address of the institution. Within 30 days after the tenancy ends and possession is delivered, the landlord must provide a full and specific statement of the basis for retaining any deposit with receipts for charges and return any remaining balance. Failure to comply entitles the tenant to the full deposit plus court costs and attorney fees.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 59.18.260; RCW 59.18.280', 'https://www.atg.wa.gov/landlord-tenant', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-005', 'WA-REAL-005', 'Real Estate Excise Tax — Graduated Rates', 'Washington imposes a Real Estate Excise Tax (REET) on the sale of real property. REET is graduated based on selling price: 1.1% on the first $525,000; 1.28% on $525,001-$1,525,000; 2.75% on $1,525,001-$3,025,000; and 3.0% on amounts over $3,025,000. Local jurisdictions may impose additional REET (typically 0.25-0.5%). REET is the seller''s obligation but may be negotiated. Certain transfers are exempt including gifts, transfers to government, and transfers to LLCs wholly owned by the grantor.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 82.45.060; RCW 82.45.033', 'https://dor.wa.gov/taxes-rates/other-taxes/real-estate-excise-tax', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-006', 'WA-REAL-006', 'Condominium Act — Formation and Governance', 'The Washington Condominium Act governs the creation, management, and termination of condominiums. Developers must prepare and record a declaration, survey map, and plans. A public offering statement must be provided to purchasers at least 7 days before closing. The association must maintain adequate insurance, hold annual meetings, maintain financial records, and prepare annual budgets. Unit owners have a right to review association records. The act addresses assessments, liens, warranties, and dispute resolution through mediation.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 64.34.010; RCW 64.34.308', 'https://app.leg.wa.gov/RCW/default.aspx?cite=64.34', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-007', 'WA-REAL-007', 'Homeowners Association Act — HOA Requirements', 'Homeowners'' associations in Washington must be governed by their declaration, bylaws, and the applicable HOA statute (RCW 64.38 for non-condo associations). HOAs must hold annual meetings, maintain financial records, prepare annual budgets, and provide members access to records. Assessments must be approved according to the governing documents. HOAs may not foreclose a lien for unpaid assessments unless the lien is at least $200 or the assessments are 12+ months delinquent. Members have a right to attend board meetings.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 64.38.010; RCW 64.38.035', 'https://app.leg.wa.gov/RCW/default.aspx?cite=64.38', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-008', 'WA-REAL-008', 'Lead Paint Disclosure — Seller and Landlord Obligations', 'For housing built before 1978, sellers and landlords must disclose known lead-based paint hazards, provide the EPA pamphlet "Protect Your Family From Lead in Your Home," allow buyers 10 days for a lead inspection (unless waived in writing), and include specific lead disclosure language in sales contracts and leases. Failure to disclose is a violation of federal law (42 USC 4852d) and enforceable in Washington under the CPA. Renovation, repair, and painting activities in pre-1978 housing must follow EPA''s RRP rule requirements.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', '42 USC 4852d; RCW 59.18.060', 'https://www.epa.gov/lead', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-009', 'WA-REAL-009', 'Seller Disclosure Statement', 'Sellers of residential real property (1-4 units) must complete and deliver a Seller Disclosure Statement to the buyer. The statement covers 10 categories: title, water, sewer/septic, structural, systems and fixtures, environment, lead paint, manufactured/mobile home, full disclosure by seller, and notice to buyer. The buyer has a 3-day rescission period (5 days if mailed) after receiving the statement. Failure to deliver the statement does not invalidate the sale but may give rise to claims for misrepresentation or fraud.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 64.06.020; RCW 64.06.030', 'https://app.leg.wa.gov/RCW/default.aspx?cite=64.06', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-010', 'WA-REAL-010', 'Mold Disclosure Requirement', 'Washington requires sellers and landlords to disclose known indoor mold problems. The Seller Disclosure Statement includes specific questions about the presence of mold or mold-like substances. Landlords must address mold issues that affect habitability under the RLTA. Property inspectors must report visible mold during home inspections. While there is no specific mold remediation standard in the RCW, the Department of Health provides guidance and significant mold contamination may constitute a code violation.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 64.06.020; RCW 59.18.060', 'https://doh.wa.gov/community-and-environment/air-quality/mold', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-011', 'WA-REAL-011', 'Tenant Screening Fees and Reporting', 'Landlords who charge tenant screening fees must provide an itemized receipt, the name and address of the screening company, and inform the applicant of their right to dispute inaccurate information. Screening fees must not exceed the actual cost of screening. Landlords must accept portable tenant screening reports (valid for 30 days) unless they offer free screening. Adverse action based on screening must comply with the Fair Credit Reporting Act and the Washington Law Against Discrimination. Source of income discrimination is prohibited.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 59.18.257; SB 5568 (2023)', 'https://www.atg.wa.gov/landlord-tenant', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-012', 'WA-REAL-012', 'Source of Income Discrimination — Housing', 'Washington prohibits discrimination in housing based on a tenant''s lawful source of income, including housing vouchers (Section 8), social security, veterans'' benefits, supplemental security income, and other public assistance. Landlords may not refuse to rent, charge different terms, or advertise limitations based on source of income. This applies to all residential housing including single-family homes, condos, and apartments. Enforcement through the Human Rights Commission or private action under the WLAD.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 49.60.222; RCW 59.18.255', 'https://www.hum.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-013', 'WA-REAL-013', 'Move-In Fee Limitations', 'Washington limits move-in fees and deposits. Landlords may not require any payment at the beginning of a tenancy that exceeds one month''s rent for the security deposit and one month''s rent for the last month''s rent (total of two months'' rent maximum at move-in, plus the first month''s rent). Landlords must offer a payment plan for move-in costs exceeding one month''s rent, allowing installments over the first six months. Non-refundable fees are prohibited except for specifically documented actual costs.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 59.18.610; SB 5160 (2021)', 'https://www.atg.wa.gov/landlord-tenant', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-014', 'WA-REAL-014', 'Foreclosure Fairness Act', 'Washington''s Foreclosure Fairness Act requires mortgage servicers to offer mediation before initiating non-judicial foreclosure on owner-occupied residential property. The borrower must be referred to a HUD-certified housing counselor. Mediation is facilitated by the Department of Commerce and explores loan modification, short sale, and other loss mitigation options. Servicers must provide 30 days'' notice to the borrower of the right to mediation. The foreclosure sale may not proceed until mediation is complete or waived.', 'REAL_ESTATE', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 61.24.163; RCW 61.24.031', 'https://www.commerce.wa.gov/building-infrastructure/housing/foreclosure-fairness/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-real-015', 'WA-REAL-015', 'Community Land Trust and Housing Equity Programs', 'Washington provides tax exemptions and support for community land trusts (CLTs) and housing equity programs to preserve affordable housing. CLTs that hold land for affordable housing purposes qualify for property tax exemptions under RCW 84.36.560. The Housing Trust Fund provides financing for affordable housing development. The Growth Management Act requires cities planning under GMA to include a housing element that addresses affordable housing needs and considers racial equity in housing access.', 'REAL_ESTATE', 'STATE', 'WA', '["NONPROFIT","LLC","CORPORATION"]', '2024-01-01', 'RCW 84.36.560; RCW 36.70A.070(2)', 'https://www.commerce.wa.gov/building-infrastructure/housing/', 1);

-- ============================================================
-- SECTION 8: CANNABIS (20 rules) — wa-cann-001 to wa-cann-020
-- ============================================================

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-001', 'WA-CANN-001', 'WSLCB Cannabis License Application Process', 'Cannabis license applications are submitted to the WSLCB and undergo a multi-step review including personal and criminal background checks, financial disclosure and source of funds review, premises inspection, local authority approval, and compliance plan review. Application fees range from $250 to $1,381 depending on license type. Processing time is typically 3-6 months. The WSLCB caps the total number of retail licenses by county based on population and may issue a moratorium on new licenses in any category.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.331; WAC 314-55-020', 'https://lcb.wa.gov/mjlicense/marijuana-licensing', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-002', 'WA-CANN-002', 'Cannabis Traceability — Seed-to-Sale Tracking', 'All licensed cannabis businesses must use the state-mandated traceability system (currently BioTrackTHC transitioning to METRC) to track every plant and product from seed/clone through final sale or destruction. Every transfer, conversion, destruction, and sale must be recorded in the system within 24 hours. Each plant must have a unique tag at the immature and flowering stages. Inventory discrepancies exceeding 5% trigger mandatory investigation and reporting to the WSLCB. System outages must be documented and reconciled.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.345; WAC 314-55-083(4)', 'https://lcb.wa.gov/mjtraceability/traceability', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-003', 'WA-CANN-003', 'Cannabis Excise Tax — 37% Rate', 'Washington imposes a 37% cannabis excise tax on the retail sale of usable marijuana, marijuana concentrates, and marijuana-infused products. The tax is calculated on the selling price and is in addition to applicable state and local sales taxes (approximately 10% combined). The excise tax is the retailer''s obligation and must be itemized on receipts. Revenue is distributed to: healthcare (52%), education (26%), substance abuse prevention (12.5%), and local governments (9.5%). Monthly tax returns required.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.535; RCW 69.50.540', 'https://dor.wa.gov/taxes-rates/other-taxes/marijuana-tax', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-004', 'WA-CANN-004', 'Cannabis Testing Requirements — Quality Assurance', 'All cannabis products must undergo mandatory testing at a WSLCB-certified lab before sale. Required tests include potency (THC and CBD levels), moisture content, foreign matter, microbiological screening (E. coli, Salmonella), mycotoxins, heavy metals (lead, arsenic, cadmium, mercury), pesticide residue (59 analytes), and residual solvents for concentrates. Products failing any test may not be sold and must be destroyed or remediated if allowed. Testing labs must maintain ISO 17025 accreditation.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 314-55-102; WAC 314-55-1025', 'https://lcb.wa.gov/mjtesting/testing', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-005', 'WA-CANN-005', 'Cannabis Advertising Restrictions', 'Cannabis advertising is prohibited on any medium where 30% or more of the audience is under 21. Advertising may not make health or medical claims, use images attractive to minors (cartoons, toys, animals), depict consumption, or include testimonials. Billboards within 1,000 feet of schools, playgrounds, or childcare centers are prohibited. All advertising must include the WSLCB license number and the warning: "This product has intoxicating effects and may be habit forming." Digital advertising must include age-gate verification.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 314-55-155; RCW 69.50.369', 'https://lcb.wa.gov/mj-education/marijuana-advertising', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-006', 'WA-CANN-006', 'Cannabis Social Equity Program', 'Washington''s social equity program prioritizes cannabis licenses for applicants from communities disproportionately impacted by cannabis prohibition. Eligible applicants must have been convicted of a cannabis offense (or have an immediate family member who was) and lived in a disproportionately impacted area. Benefits include reduced licensing fees, technical assistance, and priority processing. The WSLCB issues social equity licenses from the existing license cap. The program addresses racial disparities in cannabis enforcement.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.335; SB 5080 (2023)', 'https://lcb.wa.gov/mjlicense/social-equity', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-007', 'WA-CANN-007', 'Cannabis DUI — Workplace Impairment Policies', 'Washington sets a per se DUI threshold of 5 nanograms of THC per milliliter of blood. Employers may maintain drug-free workplace policies and test for cannabis impairment, even though recreational use is legal. However, beginning January 1, 2024, Washington prohibits employers from discriminating against applicants or employees based on cannabis use outside of work or based on pre-employment drug tests that detect non-psychoactive cannabis metabolites. Exceptions exist for safety-sensitive positions, federal requirements, and DOT-regulated employees.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP","NONPROFIT"]', '2024-01-01', 'RCW 46.61.502; RCW 49.44.240', 'https://app.leg.wa.gov/RCW/default.aspx?cite=49.44.240', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-008', 'WA-CANN-008', 'Cannabis Local Zoning and Buffer Zones', 'Local jurisdictions may adopt zoning ordinances governing the location of cannabis businesses, including establishing additional buffer zones beyond the state-mandated 1,000-foot restriction from schools and other sensitive areas. Cities and counties may ban cannabis businesses entirely or limit their number. If no local ban exists, the WSLCB will issue licenses. Licensees must operate only from the approved premises address. Any change in location requires WSLCB approval and compliance with updated local zoning requirements.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.331(8); WAC 314-55-020(12)', 'https://lcb.wa.gov/mjlicense/marijuana-licensing', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-009', 'WA-CANN-009', 'Cannabis Packaging and Labeling Requirements', 'All cannabis products must be sold in child-resistant, opaque, resealable packaging. Labels must include: product name, license number, lot/batch number, harvest date, testing results (THC/CBD percentages), net weight, allergen warnings (for edibles), universal symbol indicating the product contains cannabis, and mandatory warning statements. Edible packaging may not be designed to be appealing to children. Labels may not include false claims, unsubstantiated health statements, or images of consumption.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 314-55-105; WAC 314-55-106', 'https://lcb.wa.gov/mj-education/packaging-and-labeling', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-010', 'WA-CANN-010', 'Cannabis Security Requirements', 'Licensed cannabis premises must maintain a comprehensive security system including commercial-grade locks, alarm systems monitored by a licensed security company, surveillance cameras covering all areas where cannabis is grown, processed, stored, or sold, and video recording retained for at least 45 days. Cameras must capture clear images in all lighting conditions. Restricted areas must be clearly marked and accessible only to authorized personnel. Security plans must be submitted with the license application and updated as needed.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 314-55-083(11); WAC 314-55-083(12)', 'https://lcb.wa.gov/mjlicense/marijuana-licensing', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-011', 'WA-CANN-011', 'Cannabis Transportation Manifest Requirements', 'All cannabis being transported between licensed premises must be accompanied by a transport manifest generated from the traceability system. The manifest must include origin and destination license numbers, product description, quantities, batch/lot numbers, vehicle description, driver identification, and estimated departure and arrival times. Only employees of licensed businesses may transport cannabis. Cannabis must be transported in a locked, opaque container in a vehicle with no visible cannabis advertising.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 314-55-083(6); WAC 314-55-085', 'https://lcb.wa.gov/mj-education/transportation', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-012', 'WA-CANN-012', 'Cannabis Edible Product Limits', 'Cannabis-infused edible products are limited to 10 milligrams of THC per serving and 100 milligrams of THC per package. Each serving must be individually demarked or packaged within the overall package. Edibles may not be manufactured in forms that are attractive to minors, including candies that resemble commercially available non-cannabis products, animal shapes, or fruit shapes. Homogeneous distribution of THC throughout the product is required to ensure consistent dosing. All edibles must pass testing for potency within 20% of the label claim.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 314-55-095; WAC 314-55-105', 'https://lcb.wa.gov/mj-education/packaging-and-labeling', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-013', 'WA-CANN-013', 'Cannabis License Renewal and Compliance Inspections', 'Cannabis licenses must be renewed annually with the WSLCB. Renewal requires demonstration of continued compliance, payment of renewal fees, updated financial disclosures, and resolution of any outstanding violations. The WSLCB conducts regular compliance inspections (announced and unannounced) covering traceability records, product testing, security systems, employee verification, advertising compliance, and premises condition. Violations may result in fines ($1,000 to $10,000 per violation), license suspension, or revocation.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.331(4); WAC 314-55-515', 'https://lcb.wa.gov/enforcement/enforcement', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-014', 'WA-CANN-014', 'Cannabis Employee Background Check Requirements', 'All employees working in a cannabis licensed business must pass a criminal background check. Disqualifying offenses include felony convictions within the last 10 years and any drug-related felony. Employees must be at least 21 years of age. The WSLCB maintains a database of approved employees. New employees must apply for approval before beginning work. Background checks are valid for the duration of employment at the licensed premises. Employing unapproved individuals is a violation subject to penalties.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 314-55-035; RCW 69.50.331', 'https://lcb.wa.gov/mjlicense/marijuana-licensing', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-015', 'WA-CANN-015', 'Cannabis Waste Disposal Requirements', 'Cannabis waste must be rendered unusable and unrecognizable before disposal. Acceptable methods include grinding and mixing with at least 50% non-cannabis material (soil, food waste, paper). Waste must be documented in the traceability system including the type, quantity, and method of disposal. Liquid waste must be disposed of through approved wastewater systems. Burning of cannabis waste is prohibited. Third-party waste disposal services must be documented. WSLCB audits waste disposal records during compliance inspections.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 314-55-097; WAC 314-55-083(5)', 'https://lcb.wa.gov/mj-education/waste-disposal', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-016', 'WA-CANN-016', 'Cannabis True Party of Interest Disclosure', 'All persons or entities with a financial interest in a cannabis license must be disclosed to the WSLCB as "true parties of interest." This includes owners, investors, landlords receiving percentage-based rent, lenders with profit-sharing arrangements, and anyone receiving compensation tied to the business''s revenue. Undisclosed financial interests are grounds for license revocation. Changes in ownership or financial interest must be reported within 10 days and approved by the WSLCB before taking effect.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 314-55-035(2); RCW 69.50.331', 'https://lcb.wa.gov/mjlicense/true-party-of-interest', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-017', 'WA-CANN-017', 'Cannabis Retailer Sales Limits and ID Verification', 'Retailers may sell to any person 21 years of age or older with valid government-issued identification. Daily purchase limits: 1 ounce of usable marijuana, 7 grams of concentrates, or 16 ounces of cannabis-infused product in solid form, or 72 ounces in liquid form. Retailers must verify age for every transaction using approved ID (driver''s license, state ID, passport, military ID). Selling to minors is a criminal offense and grounds for license revocation. Point-of-sale systems must record all transactions.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.360; WAC 314-55-079', 'https://lcb.wa.gov/mj-education/retail-sales', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-018', 'WA-CANN-018', 'Cannabis Banking and Financial Reporting', 'While cannabis remains federally illegal, Washington cannabis businesses face banking challenges. Licensed businesses must maintain detailed financial records including all receipts, disbursements, bank statements (if available), tax records, and cash handling logs. Quarterly financial reports must be available to the WSLCB upon request. The state has passed legislation encouraging financial institutions to serve cannabis businesses and provides limited state-level safe harbor. Cash handling procedures must minimize theft risk and ensure accurate tax reporting.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'RCW 69.50.345; SB 5169 (2023)', 'https://lcb.wa.gov/', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-019', 'WA-CANN-019', 'Cannabis Research License', 'The WSLCB issues cannabis research licenses to entities conducting scientific research on cannabis. Research licensees may produce, possess, and administer cannabis for research purposes. Applications require a detailed research plan, qualifications of researchers, security plan, and IRB approval if human subjects are involved. Research licensees are exempt from standard producer/processor requirements but must comply with traceability, security, and reporting requirements. Research cannabis may not enter the commercial supply chain.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","NONPROFIT"]', '2024-01-01', 'RCW 69.50.372; WAC 314-55-073', 'https://lcb.wa.gov/mjlicense/marijuana-licensing', 1);

INSERT OR IGNORE INTO compliance_rules (id, code, title, description, category, level, state, entity_types, effective_date, source, source_url, is_active) VALUES
('wa-cann-020', 'WA-CANN-020', 'Cannabis Environmental Compliance', 'Cannabis cultivation operations must comply with all applicable environmental regulations including water rights (Ecology), pesticide use (WSDA), waste discharge permits, and air quality requirements for odor control. Indoor cultivation facilities with significant energy consumption may be subject to energy disclosure requirements under local building codes. Pesticide use is restricted to products approved by the WSDA for cannabis; federal EPA-registered pesticides may not be used on cannabis. Water diversion for outdoor grows requires appropriate water rights or permit-exempt well compliance.', 'CANNABIS', 'STATE', 'WA', '["LLC","CORPORATION","S_CORP","SOLE_PROPRIETORSHIP","PARTNERSHIP"]', '2024-01-01', 'WAC 314-55-083(2); RCW 15.58', 'https://lcb.wa.gov/mj-education/environmental-compliance', 1);
